var QUESTIONS_THEORY_14 = [
{type:"mcq",diff:"easy",en:{q:"What does E-commerce stand for?",opts:["Electronic Commerce","Electrical Commerce","Enterprise Commerce","Essential Commerce"],ans:0,exp:"E-commerce stands for Electronic Commerce. It refers to the buying and selling of goods or services using the internet, and the transfer of money and data to execute these transactions. It has revolutionized modern retail and business operations."},hi:{q:"ई-कॉमर्स (E-commerce) का पूर्ण रूप क्या है?",opts:["इलेक्ट्रॉनिक कॉमर्स","इलेक्ट्रिकल कॉमर्स","एंटरप्राइज कॉमर्स","एसेंशियल कॉमर्स"],ans:0,exp:"ई-कॉमर्स का अर्थ इलेक्ट्रॉनिक कॉमर्स है। यह इंटरनेट का उपयोग करके वस्तुओं या सेवाओं की खरीद और बिक्री, और इन लेन-देन को निष्पादित करने के लिए धन और डेटा के हस्तांतरण को संदर्भित करता है। इसने आधुनिक खुदरा और व्यावसायिक संचालन में क्रांति ला दी है।"}},
{type:"mcq",diff:"easy",en:{q:"Which e-commerce model involves consumers selling products directly to other consumers?",opts:["B2B","B2C","C2C","C2B"],ans:2,exp:"C2C stands for Consumer-to-Consumer. In this model, individuals sell their personal goods or services directly to other individuals, typically through a third-party online platform like OLX, Quikr, or eBay, which facilitates the transaction."},hi:{q:"किस ई-कॉमर्स मॉडल में उपभोक्ता सीधे अन्य उपभोक्ताओं को उत्पाद बेचते हैं?",opts:["B2B","B2C","C2C","C2B"],ans:2,exp:"C2C का अर्थ कंज्यूमर-टू-कंज्यूमर है। इस मॉडल में, व्यक्ति अपने व्यक्तिगत सामान या सेवाओं को सीधे अन्य व्यक्तियों को बेचते हैं, आमतौर पर OLX, Quikr, या eBay जैसे तृतीय-पक्ष ऑनलाइन प्लेटफ़ॉर्म के माध्यम से जो लेन-देन की सुविधा प्रदान करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Amazon and Flipkart are primarily examples of which e-commerce model?",opts:["B2B","B2C","C2B","C2C"],ans:1,exp:"Amazon and Flipkart are primary examples of the Business-to-Consumer (B2C) model. In this setup, a registered business sells its products directly to the end consumer through an online storefront, eliminating traditional physical retail barriers."},hi:{q:"अमेज़न (Amazon) और फ्लिपकार्ट (Flipkart) मुख्य रूप से किस ई-कॉमर्स मॉडल के उदाहरण हैं?",opts:["B2B","B2C","C2B","C2C"],ans:1,exp:"अमेज़न और फ्लिपकार्ट बिजनेस-टू-कंज्यूमर (B2C) मॉडल के प्राथमिक उदाहरण हैं। इस सेटअप में, एक पंजीकृत व्यवसाय अपने उत्पादों को एक ऑनलाइन स्टोरफ्रंट के माध्यम से सीधे अंतिम उपभोक्ता को बेचता है, जिससे पारंपरिक भौतिक खुदरा बाधाएं समाप्त हो जाती हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following describes the B2B e-commerce model?",opts:["Business selling to Consumer","Consumer selling to Business","Business selling to another Business","Government selling to Business"],ans:2,exp:"B2B stands for Business-to-Business. It describes transactions conducted directly between two businesses, such as a manufacturer selling in bulk to a wholesaler, or a wholesaler selling to a retailer via an online portal like Alibaba."},hi:{q:"निम्नलिखित में से कौन B2B ई-कॉमर्स मॉडल का वर्णन करता है?",opts:["व्यवसाय उपभोक्ता को बेच रहा है","उपभोक्ता व्यवसाय को बेच रहा है","एक व्यवसाय दूसरे व्यवसाय को बेच रहा है","सरकार व्यवसाय को बेच रही है"],ans:2,exp:"B2B का अर्थ बिजनेस-टू-बिजनेस है। यह सीधे दो व्यवसायों के बीच किए गए लेन-देन का वर्णन करता है, जैसे कि एक निर्माता थोक व्यापारी को थोक में बेचता है, या एक थोक व्यापारी अलीबाबा (Alibaba) जैसे ऑनलाइन पोर्टल के माध्यम से खुदरा विक्रेता को बेचता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the full form of COD in the context of e-commerce?",opts:["Cash on Demand","Cash on Delivery","Charge on Delivery","Cart on Delivery"],ans:1,exp:"COD stands for Cash on Delivery. It is a highly popular payment method in e-commerce where the purchaser pays for the physical goods at the exact time they are delivered to their doorstep, rather than paying online beforehand."},hi:{q:"ई-कॉमर्स के संदर्भ में COD का पूर्ण रूप क्या है?",opts:["कैश ऑन डिमांड","कैश ऑन डिलीवरी","चार्ज ऑन डिलीवरी","कार्ट ऑन डिलीवरी"],ans:1,exp:"COD का अर्थ कैश ऑन डिलीवरी है। यह ई-कॉमर्स में एक अत्यधिक लोकप्रिय भुगतान पद्धति है जहां खरीदार भौतिक वस्तुओं के लिए ऑनलाइन भुगतान करने के बजाय उनके घर पर डिलीवर होने के ठीक समय पर भुगतान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does UPI stand for in digital payments?",opts:["Unified Payments Interface","Unique Payment Identity","Universal Pay Internet","United Payments Integration"],ans:0,exp:"UPI stands for Unified Payments Interface. It is a real-time instant payment system developed by the National Payments Corporation of India (NPCI) facilitating inter-bank peer-to-peer and person-to-merchant transactions securely via mobile devices."},hi:{q:"डिजिटल भुगतान में UPI का पूर्ण रूप क्या है?",opts:["यूनिफाइड पेमेंट्स इंटरफेस (Unified Payments Interface)","यूनिक पेमेंट आइडेंटिटी","यूनिवर्सल पे इंटरनेट","यूनाइटेड पेमेंट्स इंटीग्रेशन"],ans:0,exp:"UPI का अर्थ यूनिफाइड पेमेंट्स इंटरफेस है। यह नेशनल पेमेंट्स कॉरपोरेशन ऑफ इंडिया (NPCI) द्वारा विकसित एक रीयल-टाइम त्वरित भुगतान प्रणाली है जो मोबाइल उपकरणों के माध्यम से सुरक्षित रूप से इंटर-बैंक पीयर-टू-पीयर और पर्सन-टू-मर्चेंट लेनदेन की सुविधा प्रदान करती है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary function of an online 'Shopping Cart'?",opts:["To process payment directly","To hold selected items temporarily until checkout","To deliver items to the customer","To track the shipping status"],ans:1,exp:"An online shopping cart is a piece of software that facilitates the purchase of a product or service. It temporarily stores the items selected by a user, calculates the total cost, and guides the user through the final checkout process."},hi:{q:"ऑनलाइन 'शॉपिंग कार्ट' का प्राथमिक कार्य क्या है?",opts:["सीधे भुगतान की प्रक्रिया करना","चेकआउट तक चयनित वस्तुओं को अस्थायी रूप से रखना","ग्राहक को आइटम डिलीवर करना","शिपिंग स्थिति को ट्रैक करना"],ans:1,exp:"एक ऑनलाइन शॉपिंग कार्ट एक सॉफ्टवेयर है जो किसी उत्पाद या सेवा की खरीद की सुविधा प्रदान करता है। यह अस्थायी रूप से उपयोगकर्ता द्वारा चयनित वस्तुओं को संग्रहीत करता है, कुल लागत की गणना करता है, और अंतिम चेकआउट प्रक्रिया के माध्यम से उपयोगकर्ता का मार्गदर्शन करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which term describes conducting commercial transactions using a mobile device?",opts:["E-commerce","M-commerce","T-commerce","V-commerce"],ans:1,exp:"M-commerce (Mobile Commerce) is a subcategory of e-commerce that involves buying and selling goods and services through wireless handheld devices like smartphones and tablets, offering extreme convenience and portability."},hi:{q:"मोबाइल डिवाइस का उपयोग करके वाणिज्यिक लेनदेन (commercial transactions) करने का वर्णन कौन सा शब्द करता है?",opts:["ई-कॉमर्स","एम-कॉमर्स (M-commerce)","टी-कॉमर्स","वी-कॉमर्स"],ans:1,exp:"एम-कॉमर्स (मोबाइल कॉमर्स) ई-कॉमर्स की एक उपश्रेणी है जिसमें स्मार्टफोन और टैबलेट जैसे वायरलेस हैंडहेल्ड उपकरणों के माध्यम से वस्तुओं और सेवाओं को खरीदना और बेचना शामिल है, जो अत्यधिक सुविधा और पोर्टेबिलिटी प्रदान करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does OTP stand for in secure online transactions?",opts:["One Time Password","Only Transfer Payment","Online Transaction Protocol","Over The Phone"],ans:0,exp:"OTP stands for One Time Password. It is an automatically generated numeric or alphanumeric string of characters that authenticates a user for a single transaction or login session, greatly reducing the risk of unauthorized access or fraud."},hi:{q:"सुरक्षित ऑनलाइन लेनदेन में OTP का पूर्ण रूप क्या है?",opts:["वन टाइम पासवर्ड","ओनली ट्रांसफर पेमेंट","ऑनलाइन ट्रांजेक्शन प्रोटोकॉल","ओवर द फोन"],ans:0,exp:"OTP का अर्थ वन टाइम पासवर्ड है। यह वर्णों की एक स्वचालित रूप से उत्पन्न संख्यात्मक या अल्फ़ान्यूमेरिक स्ट्रिंग है जो किसी एकल लेन-देन या लॉगिन सत्र के लिए उपयोगकर्ता को प्रमाणित करती है, जिससे अनधिकृत पहुंच या धोखाधड़ी का जोखिम बहुत कम हो जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is considered a 'Digital Product' in e-commerce?",opts:["A printed book","A physical DVD","An e-book","A laptop computer"],ans:2,exp:"An e-book is a digital product because it exists entirely in an electronic format and can be downloaded directly from the internet. Digital products require no physical inventory, packaging, or traditional shipping methods."},hi:{q:"ई-कॉमर्स में निम्नलिखित में से किसे 'डिजिटल उत्पाद' माना जाता है?",opts:["एक मुद्रित पुस्तक (Printed book)","एक भौतिक DVD","एक ई-बुक (e-book)","एक लैपटॉप कंप्यूटर"],ans:2,exp:"एक ई-बुक एक डिजिटल उत्पाद है क्योंकि यह पूरी तरह से इलेक्ट्रॉनिक प्रारूप में मौजूद है और इसे सीधे इंटरनेट से डाउनलोड किया जा सकता है। डिजिटल उत्पादों के लिए किसी भौतिक इन्वेंट्री, पैकेजिंग या पारंपरिक शिपिंग विधियों की आवश्यकता नहीं होती है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the main advantage of E-commerce for customers?",opts:["Inability to touch the product","Limited shopping hours","24/7 availability and convenience","Higher prices than physical stores"],ans:2,exp:"The main advantage of e-commerce for customers is 24/7 availability. Unlike physical stores with set opening hours, online stores are always open, allowing customers the convenience to browse, compare, and purchase items at any time."},hi:{q:"ग्राहकों के लिए ई-कॉमर्स का मुख्य लाभ क्या है?",opts:["उत्पाद को छूने में असमर्थता","सीमित खरीदारी के घंटे","24/7 उपलब्धता और सुविधा","भौतिक दुकानों की तुलना में अधिक कीमतें"],ans:2,exp:"ग्राहकों के लिए ई-कॉमर्स का मुख्य लाभ 24/7 उपलब्धता है। निर्धारित खुलने के समय वाले भौतिक स्टोरों के विपरीत, ऑनलाइन स्टोर हमेशा खुले रहते हैं, जिससे ग्राहकों को किसी भी समय आइटम ब्राउज़ करने, तुलना करने और खरीदने की सुविधा मिलती है।"}},
{type:"mcq",diff:"easy",en:{q:"What does EFT stand for in banking and e-commerce?",opts:["Electronic File Transfer","Electronic Funds Transfer","Easy Fund Transaction","External File Transmission"],ans:1,exp:"EFT stands for Electronic Funds Transfer. It is the electronic exchange or transfer of money from one account to another, either within a single financial institution or across multiple institutions, through computer-based systems."},hi:{q:"बैंकिंग और ई-कॉमर्स में EFT का पूर्ण रूप क्या है?",opts:["इलेक्ट्रॉनिक फाइल ट्रांसफर","इलेक्ट्रॉनिक फंड्स ट्रांसफर","ईज़ी फंड ट्रांजेक्शन","एक्सटर्नल फाइल ट्रांसमिशन"],ans:1,exp:"EFT का अर्थ इलेक्ट्रॉनिक फंड्स ट्रांसफर है। यह कंप्यूटर आधारित प्रणालियों के माध्यम से एक खाते से दूसरे खाते में, चाहे एक ही वित्तीय संस्थान के भीतर या कई संस्थानों में, धन का इलेक्ट्रॉनिक विनिमय या हस्तांतरण है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is an example of an E-wallet?",opts:["Cash","Google Pay / Paytm","Credit Card","Cheque"],ans:1,exp:"Google Pay and Paytm are examples of e-wallets (digital wallets). They are software-based systems that securely store users' payment information and passwords for numerous payment methods and websites, enabling quick digital transactions."},hi:{q:"निम्नलिखित में से कौन ई-वॉलेट (E-wallet) का उदाहरण है?",opts:["नकद (Cash)","गूगल पे / पेटीएम (Google Pay / Paytm)","क्रेडिट कार्ड","चेक (Cheque)"],ans:1,exp:"Google Pay और Paytm ई-वॉलेट (डिजिटल वॉलेट) के उदाहरण हैं। वे सॉफ्टवेयर-आधारित सिस्टम हैं जो कई भुगतान विधियों और वेबसाइटों के लिए उपयोगकर्ताओं की भुगतान जानकारी और पासवर्ड को सुरक्षित रूप से संग्रहीत करते हैं, जिससे त्वरित डिजिटल लेनदेन सक्षम होता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does EDI stand for in business operations?",opts:["Electronic Data Interchange","Electrical Device Interface","Enterprise Data Integration","External Data Information"],ans:0,exp:"EDI stands for Electronic Data Interchange. It is the computer-to-computer exchange of business documents (like purchase orders and invoices) in a standard electronic format between business partners, completely replacing paper documents."},hi:{q:"व्यावसायिक संचालन में EDI का पूर्ण रूप क्या है?",opts:["इलेक्ट्रॉनिक डेटा इंटरचेंज (Electronic Data Interchange)","इलेक्ट्रिकल डिवाइस इंटरफेस","एंटरप्राइज डेटा इंटीग्रेशन","एक्सटर्नल डेटा इंफॉर्मेशन"],ans:0,exp:"EDI का अर्थ इलेक्ट्रॉनिक डेटा इंटरचेंज है। यह व्यापार भागीदारों के बीच एक मानक इलेक्ट्रॉनिक प्रारूप में व्यावसायिक दस्तावेजों (जैसे खरीद आदेश और चालान) का कंप्यूटर-टू-कंप्यूटर विनिमय है, जो पूरी तरह से कागजी दस्तावेजों की जगह लेता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the visual indicator that a website is secure for entering payment details?",opts:["http:// in URL","A padlock icon and https://","Flashing banners","Pop-up ads"],ans:1,exp:"A padlock icon in the browser address bar and a URL beginning with 'https://' instead of 'http://' indicate that the site uses SSL/TLS encryption. This ensures that the sensitive payment data transmitted is securely encrypted."},hi:{q:"भुगतान विवरण दर्ज करने के लिए एक वेबसाइट सुरक्षित है, इसका दृश्य संकेतक (visual indicator) क्या है?",opts:["URL में http://","एक पैडलॉक (ताला) आइकन और https://","चमकते बैनर","पॉप-अप विज्ञापन"],ans:1,exp:"ब्राउज़र एड्रेस बार में एक पैडलॉक आइकन और 'http://' के बजाय 'https://' से शुरू होने वाला URL इंगित करता है कि साइट SSL/TLS एन्क्रिप्शन का उपयोग करती है। यह सुनिश्चित करता है कि प्रेषित संवेदनशील भुगतान डेटा सुरक्षित रूप से एन्क्रिप्ट किया गया है।"}},
{type:"mcq",diff:"easy",en:{q:"What does CVV stand for on a credit or debit card?",opts:["Card Verification Value","Code Verification Value","Card Validation Vector","Central Verification Value"],ans:0,exp:"CVV stands for Card Verification Value. It is a 3 or 4-digit anti-fraud security feature printed on the back (or front for Amex) of credit and debit cards to ensure the person making the online transaction physically possesses the card."},hi:{q:"क्रेडिट या डेबिट कार्ड पर CVV का पूर्ण रूप क्या है?",opts:["कार्ड वेरिफिकेशन वैल्यू (Card Verification Value)","कोड वेरिफिकेशन वैल्यू","कार्ड वैलिडेशन वेक्टर","सेंट्रल वेरिफिकेशन वैल्यू"],ans:0,exp:"CVV का अर्थ कार्ड वेरिफिकेशन वैल्यू है। यह क्रेडिट और डेबिट कार्ड के पीछे (या एमेक्स के लिए आगे) मुद्रित एक 3 या 4-अंकीय धोखाधड़ी-विरोधी सुरक्षा विशेषता है, ताकि यह सुनिश्चित किया जा सके कि ऑनलाइन लेनदेन करने वाले व्यक्ति के पास भौतिक रूप से कार्ड है।"}},
{type:"mcq",diff:"easy",en:{q:"In the context of E-commerce, what does 'B2G' signify?",opts:["Business to Gateway","Business to Government","Buyer to Government","Basic to General"],ans:1,exp:"B2G stands for Business-to-Government. It refers to the e-commerce model where private businesses supply goods, services, or information to government agencies, usually through online public procurement portals or bidding systems."},hi:{q:"ई-कॉमर्स के संदर्भ में, 'B2G' क्या दर्शाता है?",opts:["बिजनेस टू गेटवे","बिजनेस टू गवर्नमेंट (Business to Government)","बायर टू गवर्नमेंट","बेसिक टू जनरल"],ans:1,exp:"B2G का अर्थ बिजनेस-टू-गवर्नमेंट है। यह उस ई-कॉमर्स मॉडल को संदर्भित करता है जहां निजी व्यवसाय सरकारी एजेंसियों को वस्तुओं, सेवाओं या सूचनाओं की आपूर्ति करते हैं, आमतौर पर ऑनलाइन सार्वजनिक खरीद पोर्टल या बोली प्रणाली के माध्यम से।"}},
{type:"mcq",diff:"easy",en:{q:"What is 'Plastic Money' primarily used for in e-commerce?",opts:["Creating physical toys","Electronic payments using Credit/Debit cards","Printing 3D objects","Making loyalty cards"],ans:1,exp:"'Plastic Money' is a colloquial term for the hard plastic cards used for payments, specifically credit cards, debit cards, and prepaid cards. They are essential tools for facilitating cashless, secure electronic payments in e-commerce."},hi:{q:"ई-कॉमर्स में 'प्लास्टिक मनी' का मुख्य रूप से किस लिए उपयोग किया जाता है?",opts:["भौतिक खिलौने बनाना","क्रेडिट/डेबिट कार्ड का उपयोग करके इलेक्ट्रॉनिक भुगतान","3D ऑब्जेक्ट्स को प्रिंट करना","लॉयल्टी कार्ड बनाना"],ans:1,exp:"'प्लास्टिक मनी' भुगतान के लिए उपयोग किए जाने वाले हार्ड प्लास्टिक कार्डों के लिए एक बोलचाल का शब्द है, विशेष रूप से क्रेडिट कार्ड, डेबिट कार्ड और प्रीपेड कार्ड। वे ई-कॉमर्स में कैशलेस, सुरक्षित इलेक्ट्रॉनिक भुगतान की सुविधा के लिए आवश्यक उपकरण हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which domain extension is most commonly associated with commercial e-commerce websites worldwide?",opts:[".edu",".org",".com",".gov"],ans:2,exp:"The '.com' domain extension originally stood for 'commercial'. It is the most popular and globally recognized Top-Level Domain (TLD) used by businesses and e-commerce websites to establish their online retail presence."},hi:{q:"दुनिया भर में वाणिज्यिक ई-कॉमर्स वेबसाइटों से सबसे अधिक कौन सा डोमेन एक्सटेंशन जुड़ा है?",opts:[".edu",".org",".com",".gov"],ans:2,exp:"'.com' डोमेन एक्सटेंशन मूल रूप से 'commercial' के लिए था। यह व्यवसायों और ई-कॉमर्स वेबसाइटों द्वारा अपनी ऑनलाइन खुदरा उपस्थिति स्थापित करने के लिए उपयोग किया जाने वाला सबसे लोकप्रिय और विश्व स्तर पर मान्यता प्राप्त टॉप-लेवल डोमेन (TLD) है।"}},
{type:"mcq",diff:"easy",en:{q:"What does PIN stand for in banking?",opts:["Personal Identification Number","Private Information Network","Primary Identification Node","Payment Interface Number"],ans:0,exp:"PIN stands for Personal Identification Number. It is a secret numeric password shared between a user and a system to authenticate the user to the system, heavily used in ATM withdrawals and debit card transactions."},hi:{q:"बैंकिंग में PIN का पूर्ण रूप क्या है?",opts:["पर्सनल आइडेंटिफिकेशन नंबर (Personal Identification Number)","प्राइवेट इंफॉर्मेशन नेटवर्क","प्राइमरी आइडेंटिफिकेशन नोड","पेमेंट इंटरफेस नंबर"],ans:0,exp:"PIN का अर्थ पर्सनल आइडेंटिफिकेशन नंबर है। यह एक गुप्त संख्यात्मक पासवर्ड है जिसे उपयोगकर्ता को सिस्टम में प्रमाणित करने के लिए उपयोगकर्ता और सिस्टम के बीच साझा किया जाता है, जिसका उपयोग एटीएम निकासी और डेबिट कार्ड लेनदेन में भारी मात्रा में किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is a major disadvantage of E-commerce?",opts:["Lower overhead costs","Inability to physically inspect products before purchase","Ability to compare prices easily","Global reach"],ans:1,exp:"A significant drawback of e-commerce is the inability for customers to physically touch, feel, or try on products (like clothing or furniture) prior to making a purchase, which can sometimes lead to dissatisfaction and high return rates."},hi:{q:"निम्नलिखित में से कौन ई-कॉमर्स का एक बड़ा नुकसान (disadvantage) है?",opts:["कम ओवरहेड लागत","खरीद से पहले उत्पादों का भौतिक रूप से निरीक्षण करने में असमर्थता","कीमतों की आसानी से तुलना करने की क्षमता","वैश्विक पहुंच"],ans:1,exp:"ई-कॉमर्स की एक महत्वपूर्ण खामी ग्राहकों के लिए खरीदारी करने से पहले उत्पादों (जैसे कपड़े या फर्नीचर) को भौतिक रूप से छूने, महसूस करने या आज़माने में असमर्थता है, जिससे कभी-कभी असंतोष और उच्च वापसी (return) दर हो सकती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which device is absolutely necessary for conducting M-commerce?",opts:["A desktop PC","A landline telephone","A smartphone or tablet with internet","A dot-matrix printer"],ans:2,exp:"M-commerce (Mobile Commerce) specifically relies on wireless handheld devices. Therefore, a smartphone, tablet, or PDA with an active internet connection is the fundamental hardware requirement to browse and shop via mobile apps."},hi:{q:"एम-कॉमर्स (M-commerce) के संचालन के लिए कौन सा उपकरण बिल्कुल आवश्यक है?",opts:["एक डेस्कटॉप पीसी","एक लैंडलाइन टेलीफोन","इंटरनेट के साथ एक स्मार्टफोन या टैबलेट","एक डॉट-मैट्रिक्स प्रिंटर"],ans:2,exp:"एम-कॉमर्स (मोबाइल कॉमर्स) विशेष रूप से वायरलेस हैंडहेल्ड उपकरणों पर निर्भर करता है। इसलिए, एक सक्रिय इंटरनेट कनेक्शन वाला स्मार्टफोन, टैबलेट या पीडीए मोबाइल ऐप के माध्यम से ब्राउज़ करने और खरीदारी करने के लिए मूलभूत हार्डवेयर आवश्यकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Who is the 'seller' in a typical B2C transaction?",opts:["An individual consumer","A registered business enterprise","A government agency","An independent freelancer"],ans:1,exp:"In a Business-to-Consumer (B2C) transaction, the 'seller' is a registered business enterprise or company that manufactures or retails products, while the 'buyer' is the individual end-user purchasing for personal consumption."},hi:{q:"एक विशिष्ट B2C लेनदेन में 'विक्रेता' (seller) कौन होता है?",opts:["एक व्यक्तिगत उपभोक्ता","एक पंजीकृत व्यावसायिक उद्यम (registered business enterprise)","एक सरकारी एजेंसी","एक स्वतंत्र फ्रीलांसर"],ans:1,exp:"बिजनेस-टू-कंज्यूमर (B2C) लेनदेन में, 'विक्रेता' एक पंजीकृत व्यावसायिक उद्यम या कंपनी है जो उत्पादों का निर्माण या खुदरा बिक्री करती है, जबकि 'खरीदार' व्यक्तिगत उपभोग के लिए खरीदारी करने वाला अंतिम उपयोगकर्ता होता है।"}},
{type:"mcq",diff:"easy",en:{q:"What type of business model does a freelance graphic designer use when selling logo designs to a marketing agency?",opts:["C2C","C2B","B2B","B2C"],ans:1,exp:"This is an example of Consumer-to-Business (C2B). In C2B, an individual consumer or freelancer creates value, products, or services and sells them to a larger business or organization that requires them."},hi:{q:"एक फ्रीलांस ग्राफिक डिजाइनर मार्केटिंग एजेंसी को लोगो डिजाइन बेचते समय किस प्रकार के बिजनेस मॉडल का उपयोग करता है?",opts:["C2C","C2B","B2B","B2C"],ans:1,exp:"यह कंज्यूमर-टू-बिजनेस (C2B) का एक उदाहरण है। C2B में, एक व्यक्तिगत उपभोक्ता या फ्रीलांसर मूल्य, उत्पाद या सेवाएँ बनाता है और उन्हें किसी बड़े व्यवसाय या संगठन को बेचता है जिसे उनकी आवश्यकता होती है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a prerequisite for a customer to shop online?",opts:["A physical store address","An internet connection and a compatible device","A printed catalog","A government ID card"],ans:1,exp:"To access any e-commerce platform or online store, a customer strictly requires a compatible digital device (like a PC or smartphone) and an active internet connection to browse the website and securely transmit transaction data."},hi:{q:"किसी ग्राहक को ऑनलाइन खरीदारी करने के लिए पूर्व शर्त (prerequisite) क्या है?",opts:["एक भौतिक दुकान का पता","एक इंटरनेट कनेक्शन और एक संगत उपकरण (compatible device)","एक मुद्रित कैटलॉग","एक सरकारी आईडी कार्ड"],ans:1,exp:"किसी भी ई-कॉमर्स प्लेटफॉर्म या ऑनलाइन स्टोर तक पहुंचने के लिए, ग्राहक को वेबसाइट ब्राउज़ करने और सुरक्षित रूप से लेनदेन डेटा संचारित करने के लिए एक संगत डिजिटल डिवाइस (जैसे पीसी या स्मार्टफोन) और एक सक्रिय इंटरनेट कनेक्शन की आवश्यकता होती है।"}},
{type:"mcq",diff:"easy",en:{q:"What should you NEVER share with anyone to maintain online payment security?",opts:["Your email address","Your bank branch name","Your OTP and PIN","Your shipping address"],ans:2,exp:"OTPs (One Time Passwords) and PINs (Personal Identification Numbers) are confidential security factors meant only for the cardholder. Sharing them compromises the account and allows scammers to bypass security and steal funds."},hi:{q:"ऑनलाइन भुगतान सुरक्षा बनाए रखने के लिए आपको कभी भी किसी के साथ क्या साझा नहीं करना चाहिए?",opts:["अपना ईमेल पता","अपनी बैंक शाखा का नाम","अपना OTP और PIN","अपना शिपिंग पता"],ans:2,exp:"OTP (वन टाइम पासवर्ड) और PIN (पर्सनल आइडेंटिफिकेशन नंबर) गोपनीय सुरक्षा कारक हैं जो केवल कार्डधारक के लिए हैं। उन्हें साझा करने से खाते से समझौता होता है और स्कैमर्स को सुरक्षा बायपास करने और धन चोरी करने की अनुमति मिलती है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is NOT an E-commerce platform?",opts:["Flipkart","Amazon","Microsoft Paint","eBay"],ans:2,exp:"Microsoft Paint is a simple raster graphics editor and drawing program included with Windows. Flipkart, Amazon, and eBay are all massive online marketplaces designed for buying and selling goods (E-commerce platforms)."},hi:{q:"निम्नलिखित में से कौन ई-कॉमर्स प्लेटफॉर्म नहीं है?",opts:["फ्लिपकार्ट (Flipkart)","अमेज़न (Amazon)","माइक्रोसॉफ्ट पेंट (Microsoft Paint)","ईबे (eBay)"],ans:2,exp:"माइक्रोसॉफ्ट पेंट विंडोज के साथ शामिल एक सरल रास्टर ग्राफिक्स एडिटर और ड्राइंग प्रोग्राम है। फ्लिपकार्ट, अमेज़ॅन और ईबे सभी विशाल ऑनलाइन मार्केटप्लेस हैं जो सामान खरीदने और बेचने (ई-कॉमर्स प्लेटफॉर्म) के लिए डिज़ाइन किए गए हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which feature allows buyers to read about others' experiences with a product on an e-commerce site?",opts:["Shopping Cart","Customer Reviews and Ratings","Payment Gateway","Checkout Page"],ans:1,exp:"Customer reviews and ratings are interactive features on e-commerce sites where previous buyers leave feedback, comments, and star ratings about a product. This builds trust and helps new buyers make informed decisions."},hi:{q:"कौन सी सुविधा खरीदारों को ई-कॉमर्स साइट पर उत्पाद के साथ दूसरों के अनुभवों के बारे में पढ़ने की अनुमति देती है?",opts:["शॉपिंग कार्ट","ग्राहक समीक्षाएं और रेटिंग (Customer Reviews and Ratings)","पेमेंट गेटवे","चेकआउट पेज"],ans:1,exp:"ग्राहक समीक्षाएं और रेटिंग ई-कॉमर्स साइटों पर संवादात्मक विशेषताएं हैं जहां पिछले खरीदार किसी उत्पाद के बारे में प्रतिक्रिया, टिप्पणियां और स्टार रेटिंग छोड़ते हैं। यह विश्वास बनाता है और नए खरीदारों को सूचित निर्णय लेने में मदद करता है।"}},
{type:"tf",diff:"easy",en:{q:"E-commerce websites operate 24 hours a day, 7 days a week.",opts:["True","False"],ans:0,exp:"True. Unlike traditional brick-and-mortar stores that have fixed opening and closing hours, e-commerce websites run continuously on web servers, allowing customers to shop at any time of day or night."},hi:{q:"ई-कॉमर्स वेबसाइटें दिन के 24 घंटे, सप्ताह के 7 दिन काम करती हैं।",opts:["सही","गलत"],ans:0,exp:"सही। पारंपरिक ईंट-और-मोर्टार स्टोरों के विपरीत, जिनमें खुलने और बंद होने का समय निश्चित होता है, ई-कॉमर्स वेबसाइटें लगातार वेब सर्वर पर चलती हैं, जिससे ग्राहक दिन या रात किसी भी समय खरीदारी कर सकते हैं।"}},
{type:"tf",diff:"easy",en:{q:"It is safe to save your bank passwords and CVV numbers in a public text file.",opts:["True","False"],ans:1,exp:"False. Banking passwords, PINs, and CVV numbers are highly sensitive. Storing them in a public or unencrypted file exposes you to severe security risks, identity theft, and financial fraud."},hi:{q:"अपने बैंक पासवर्ड और CVV नंबर को सार्वजनिक टेक्स्ट फ़ाइल में सहेजना सुरक्षित है।",opts:["सही","गलत"],ans:1,exp:"गलत। बैंकिंग पासवर्ड, पिन और सीवीवी नंबर अत्यधिक संवेदनशील होते हैं। उन्हें सार्वजनिक या बिना एन्क्रिप्ट की गई फ़ाइल में संग्रहीत करने से आपको गंभीर सुरक्षा जोखिमों, पहचान की चोरी और वित्तीय धोखाधड़ी का सामना करना पड़ सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary role of a 'Payment Gateway' in e-commerce?",opts:["To deliver goods physically","To authorize credit card or direct payments securely","To design the e-commerce website","To manage the warehouse inventory"],ans:1,exp:"A payment gateway is an essential e-commerce service that securely transmits transaction information to acquiring banks and authorizes payments for e-businesses, acting as the digital equivalent of a physical point-of-sale terminal."},hi:{q:"ई-कॉमर्स में 'पेमेंट गेटवे' (Payment Gateway) की प्राथमिक भूमिका क्या है?",opts:["सामान को भौतिक रूप से वितरित करना","क्रेडिट कार्ड या सीधे भुगतान को सुरक्षित रूप से अधिकृत (authorize) करना","ई-कॉमर्स वेबसाइट डिजाइन करना","वेयरहाउस इन्वेंट्री का प्रबंधन करना"],ans:1,exp:"पेमेंट गेटवे एक आवश्यक ई-कॉमर्स सेवा है जो अधिग्रहण करने वाले बैंकों (acquiring banks) को सुरक्षित रूप से लेनदेन की जानकारी प्रेषित करती है और ई-व्यवसायों के लिए भुगतान को अधिकृत करती है, जो भौतिक पॉइंट-ऑफ़-सेल टर्मिनल के डिजिटल समकक्ष के रूप में कार्य करती है।"}},
{type:"mcq",diff:"medium",en:{q:"What does SSL stand for in website security?",opts:["Secure Sockets Layer","System Security Layer","Safe Server Link","Standard Security Logic"],ans:0,exp:"SSL stands for Secure Sockets Layer. It is a standard security protocol for establishing an encrypted link between a web server and a browser, ensuring that all data passed between them remains private and integral."},hi:{q:"वेबसाइट सुरक्षा में SSL का पूर्ण रूप क्या है?",opts:["सिक्योर सॉकेट्स लेयर (Secure Sockets Layer)","सिस्टम सिक्योरिटी लेयर","सेफ सर्वर लिंक","स्टैंडर्ड सिक्योरिटी लॉजिक"],ans:0,exp:"SSL का अर्थ सिक्योर सॉकेट्स लेयर है। यह वेब सर्वर और ब्राउज़र के बीच एक एन्क्रिप्टेड लिंक स्थापित करने के लिए एक मानक सुरक्षा प्रोटोकॉल है, जो यह सुनिश्चित करता है कि उनके बीच पारित सभी डेटा निजी और सुरक्षित रहे।"}},
{type:"mcq",diff:"medium",en:{q:"Which term describes the reversal of a credit card transaction initiated by the cardholder's bank?",opts:["Refund","Chargeback","Wire Transfer","Direct Debit"],ans:1,exp:"A chargeback is a forced reversal of a transaction, initiated by the cardholder's issuing bank, often due to a dispute or fraud claim. Unlike a standard refund given by the merchant, a chargeback penalizes the merchant."},hi:{q:"कार्डधारक के बैंक द्वारा शुरू किए गए क्रेडिट कार्ड लेनदेन को उलटने का वर्णन कौन सा शब्द करता है?",opts:["रिफंड (Refund)","चार्जबैक (Chargeback)","वायर ट्रांसफर (Wire Transfer)","डायरेक्ट डेबिट (Direct Debit)"],ans:1,exp:"चार्जबैक लेनदेन का एक जबरन उलटफेर है, जो कार्डधारक के जारीकर्ता बैंक द्वारा शुरू किया जाता है, अक्सर विवाद या धोखाधड़ी के दावे के कारण। मर्चेंट द्वारा दिए गए मानक रिफंड के विपरीत, चार्जबैक मर्चेंट को दंडित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the main purpose of Cryptography in e-commerce?",opts:["To make the website load faster","To secure data through encryption so unauthorized users cannot read it","To store product images","To compress video files"],ans:1,exp:"Cryptography ensures data confidentiality and integrity by encrypting sensitive information, such as passwords and credit card details, turning it into unreadable ciphertext that only authorized parties with the decryption key can access."},hi:{q:"ई-कॉमर्स में क्रिप्टोग्राफी (Cryptography) का मुख्य उद्देश्य क्या है?",opts:["वेबसाइट को तेज़ी से लोड करने के लिए","एन्क्रिप्शन के माध्यम से डेटा को सुरक्षित करने के लिए ताकि अनधिकृत उपयोगकर्ता इसे पढ़ न सकें","उत्पाद छवियों को संग्रहीत करने के लिए","वीडियो फ़ाइलों को संपीड़ित (compress) करने के लिए"],ans:1,exp:"क्रिप्टोग्राफी पासवर्ड और क्रेडिट कार्ड विवरण जैसी संवेदनशील जानकारी को एन्क्रिप्ट करके डेटा गोपनीयता और अखंडता सुनिश्चित करती है, इसे अपठनीय सिफरटेक्स्ट में बदल देती है जिसे केवल डिक्रिप्शन कुंजी वाले अधिकृत पक्ष ही एक्सेस कर सकते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"In e-commerce, what is a Merchant Account?",opts:["A customer's shopping profile","A special bank account enabling a business to accept credit card payments","An email account for customer service","A social media account for marketing"],ans:1,exp:"A merchant account is a specialized commercial bank account that establishes an agreement between a retailer and an acquiring bank, explicitly allowing the business to accept and process electronic credit and debit card transactions."},hi:{q:"ई-कॉमर्स में, मर्चेंट अकाउंट (Merchant Account) क्या है?",opts:["ग्राहक की शॉपिंग प्रोफ़ाइल","एक विशेष बैंक खाता जो व्यवसाय को क्रेडिट कार्ड से भुगतान स्वीकार करने में सक्षम बनाता है","ग्राहक सेवा के लिए एक ईमेल खाता","मार्केटिंग के लिए सोशल मीडिया अकाउंट"],ans:1,exp:"एक मर्चेंट अकाउंट एक विशेष वाणिज्यिक बैंक खाता है जो एक खुदरा विक्रेता और एक अधिग्रहण करने वाले बैंक के बीच एक समझौता स्थापित करता है, जो व्यवसाय को स्पष्ट रूप से इलेक्ट्रॉनिक क्रेडिट और डेबिट कार्ड लेनदेन को स्वीकार करने और संसाधित करने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the SET protocol stand for?",opts:["Safe Electronic Transfer","Secure Electronic Transaction","System Electronic Transit","Standard E-commerce Terminal"],ans:1,exp:"SET stands for Secure Electronic Transaction. Developed by Visa and MasterCard, it is a cryptographic protocol designed to ensure the absolute security and privacy of credit card transactions conducted over unsecured networks like the Internet."},hi:{q:"SET प्रोटोकॉल का पूर्ण रूप क्या है?",opts:["सेफ इलेक्ट्रॉनिक ट्रांसफर","सिक्योर इलेक्ट्रॉनिक ट्रांजेक्शन (Secure Electronic Transaction)","सिस्टम इलेक्ट्रॉनिक ट्रांजिट","स्टैंडर्ड ई-कॉमर्स टर्मिनल"],ans:1,exp:"SET का अर्थ है सिक्योर इलेक्ट्रॉनिक ट्रांजैक्शन। वीज़ा और मास्टरकार्ड द्वारा विकसित, यह एक क्रिप्टोग्राफ़िक प्रोटोकॉल है जिसे इंटरनेट जैसे असुरक्षित नेटवर्क पर किए गए क्रेडिट कार्ड लेनदेन की पूर्ण सुरक्षा और गोपनीयता सुनिश्चित करने के लिए डिज़ाइन किया गया है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is an example of a fraudulent attempt to obtain sensitive information by disguising as a trustworthy entity in an electronic communication?",opts:["Spoofing","Phishing","SEO","Dropshipping"],ans:1,exp:"Phishing is a highly prevalent cyber-attack where criminals impersonate legitimate institutions (like banks or e-commerce sites) via emails or text messages to trick victims into revealing sensitive data like passwords and credit card numbers."},hi:{q:"इलेक्ट्रॉनिक संचार में भरोसेमंद इकाई (trustworthy entity) के रूप में खुद को प्रच्छन्न करके संवेदनशील जानकारी प्राप्त करने के धोखाधड़ी वाले प्रयास का उदाहरण निम्नलिखित में से कौन सा है?",opts:["स्पूफिंग (Spoofing)","फिशिंग (Phishing)","एसईओ (SEO)","ड्रॉपशिपिंग (Dropshipping)"],ans:1,exp:"फिशिंग एक अत्यधिक प्रचलित साइबर-हमला है जहां अपराधी पीड़ित को पासवर्ड और क्रेडिट कार्ड नंबर जैसे संवेदनशील डेटा को प्रकट करने के लिए ईमेल या टेक्स्ट संदेशों के माध्यम से वैध संस्थानों (जैसे बैंक या ई-कॉमर्स साइट) का रूप धारण करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'E-procurement'?",opts:["Buying personal groceries online","The business-to-business online requisitioning and purchasing of supplies","Selling digital music","Returning defective goods"],ans:1,exp:"E-procurement is the B2B or B2G sale and purchase of supplies, work, and services through the Internet. It modernizes the supply chain by automating corporate purchasing processes, reducing costs, and increasing efficiency."},hi:{q:"'ई-प्रोक्योरमेंट' (E-procurement) क्या है?",opts:["व्यक्तिगत किराने का सामान ऑनलाइन खरीदना","आपूर्ति की व्यापार-से-व्यापार (B2B) ऑनलाइन मांग और खरीद","डिजिटल संगीत बेचना","दोषपूर्ण माल वापस करना"],ans:1,exp:"ई-प्रोक्योरमेंट इंटरनेट के माध्यम से आपूर्ति, काम और सेवाओं की B2B या B2G बिक्री और खरीद है। यह कॉर्पोरेट खरीद प्रक्रियाओं को स्वचालित करके, लागत को कम करके और दक्षता बढ़ाकर आपूर्ति श्रृंखला (supply chain) को आधुनिक बनाता है।"}},
{type:"mcq",diff:"medium",en:{q:"In an e-commerce transaction, what is the role of an 'Acquiring Bank'?",opts:["It issues the credit card to the customer","It maintains the merchant's bank account and processes the card transactions","It regulates internet speeds","It delivers the physical product"],ans:1,exp:"The Acquiring Bank (or acquirer) is a financial institution that maintains the merchant's bank account. It receives the transaction request from the payment gateway, requests authorization from the issuing bank, and ultimately deposits funds into the merchant's account."},hi:{q:"ई-कॉमर्स लेनदेन में, 'अधिग्रहणकर्ता बैंक' (Acquiring Bank) की क्या भूमिका होती है?",opts:["यह ग्राहक को क्रेडिट कार्ड जारी करता है","यह मर्चेंट का बैंक खाता बनाए रखता है और कार्ड लेनदेन को प्रोसेस करता है","यह इंटरनेट की गति को नियंत्रित करता है","यह भौतिक उत्पाद वितरित करता है"],ans:1,exp:"एक्वायरिंग बैंक (या एक्वायरर) एक वित्तीय संस्थान है जो व्यापारी का बैंक खाता बनाए रखता है। यह भुगतान गेटवे से लेनदेन का अनुरोध प्राप्त करता है, जारीकर्ता बैंक से प्राधिकरण का अनुरोध करता है, और अंततः व्यापारी के खाते में धन जमा करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which concept ensures that a sender cannot deny having sent a message or initiated a transaction?",opts:["Authentication","Confidentiality","Non-repudiation","Integrity"],ans:2,exp:"Non-repudiation is a legal and technical concept in cryptography (achieved via digital signatures) ensuring that the originator of a statement or transaction cannot later falsely deny their involvement or authorship."},hi:{q:"कौन सी अवधारणा यह सुनिश्चित करती है कि प्रेषक संदेश भेजने या लेन-देन शुरू करने से इनकार नहीं कर सकता?",opts:["प्रमाणीकरण (Authentication)","गोपनीयता (Confidentiality)","गैर-अस्वीकरण (Non-repudiation)","अखंडता (Integrity)"],ans:2,exp:"गैर-अस्वीकरण (Non-repudiation) क्रिप्टोग्राफी (डिजिटल हस्ताक्षर के माध्यम से प्राप्त) में एक कानूनी और तकनीकी अवधारणा है जो यह सुनिश्चित करती है कि किसी बयान या लेन-देन का प्रवर्तक बाद में अपनी भागीदारी या लेखकत्व से झूठा इनकार नहीं कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Dropshipping' in e-commerce?",opts:["A shipping method using drones","A retail fulfillment method where a store doesn't keep the products it sells in stock","A technique to drop prices instantly","Shipping goods over water"],ans:1,exp:"Dropshipping is a supply chain management method. Instead of storing inventory, the retailer purchases the item from a third-party supplier only when a customer makes an order, and the supplier ships it directly to the customer."},hi:{q:"ई-कॉमर्स में 'ड्रॉपशिपिंग' (Dropshipping) क्या है?",opts:["ड्रोन का उपयोग करके एक शिपिंग विधि","एक खुदरा पूर्ति पद्धति जहां कोई स्टोर बेचे जाने वाले उत्पादों को स्टॉक में नहीं रखता है","कीमतों को तुरंत कम करने की तकनीक","पानी के ऊपर माल की शिपिंग"],ans:1,exp:"ड्रॉपशिपिंग एक आपूर्ति श्रृंखला प्रबंधन विधि है। इन्वेंट्री को स्टोर करने के बजाय, रिटेलर किसी तृतीय-पक्ष आपूर्तिकर्ता से तभी आइटम खरीदता है जब कोई ग्राहक ऑर्डर करता है, और आपूर्तिकर्ता इसे सीधे ग्राहक को भेज देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the 'Bounce Rate' metric indicate for an e-commerce website?",opts:["The speed at which the site loads","The percentage of visitors who navigate away after viewing only one page","The number of bad cheques received","The rate of returned products"],ans:1,exp:"Bounce rate is a crucial web analytics metric. It represents the percentage of visitors who enter the site and then leave ('bounce') rather than continuing to view other pages within the same e-commerce site, often indicating poor landing page relevance."},hi:{q:"ई-कॉमर्स वेबसाइट के लिए 'बाउंस रेट' (Bounce Rate) मीट्रिक क्या दर्शाता है?",opts:["वह गति जिस पर साइट लोड होती है","केवल एक पृष्ठ देखने के बाद दूर जाने वाले आगंतुकों (visitors) का प्रतिशत","प्राप्त खराब चेकों की संख्या","लौटाए गए उत्पादों की दर"],ans:1,exp:"बाउंस दर एक महत्वपूर्ण वेब एनालिटिक्स मीट्रिक है। यह उन आगंतुकों के प्रतिशत का प्रतिनिधित्व करता है जो साइट में प्रवेश करते हैं और फिर उसी ई-कॉमर्स साइट के भीतर अन्य पृष्ठों को देखने के बजाय छोड़ देते हैं ('बाउंस'), जो अक्सर खराब लैंडिंग पृष्ठ प्रासंगिकता को दर्शाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary function of SEO in e-commerce?",opts:["To process credit card payments","To improve a website's visibility and ranking on search engine results pages","To encrypt customer passwords","To manage warehouse logistics"],ans:1,exp:"SEO (Search Engine Optimization) involves modifying website content, tags, and structure to rank higher organically on search engines like Google. High visibility leads to increased web traffic, which is essential for e-commerce sales."},hi:{q:"ई-कॉमर्स में SEO का प्राथमिक कार्य क्या है?",opts:["क्रेडिट कार्ड से भुगतान प्रोसेस करने के लिए","खोज इंजन परिणाम पृष्ठों (search engine results pages) पर वेबसाइट की दृश्यता और रैंकिंग में सुधार करने के लिए","ग्राहक के पासवर्ड को एन्क्रिप्ट करने के लिए","गोदाम रसद (logistics) का प्रबंधन करने के लिए"],ans:1,exp:"SEO (सर्च इंजन ऑप्टिमाइजेशन) में Google जैसे सर्च इंजनों पर व्यवस्थित रूप से उच्च रैंक करने के लिए वेबसाइट की सामग्री, टैग और संरचना को संशोधित करना शामिल है। उच्च दृश्यता से वेब ट्रैफ़िक बढ़ता है, जो ई-कॉमर्स बिक्री के लिए आवश्यक है।"}},
{type:"mcq",diff:"medium",en:{q:"What do e-commerce websites use to track items in a user's shopping cart across multiple pages?",opts:["Cookies","Viruses","Firewalls","MAC Addresses"],ans:0,exp:"Cookies are small text files stored on the user's browser by the web server. They maintain session state, allowing the e-commerce site to remember user preferences, login status, and importantly, the items added to the virtual shopping cart."},hi:{q:"ई-कॉमर्स वेबसाइटें कई पृष्ठों पर उपयोगकर्ता के शॉपिंग कार्ट में आइटम को ट्रैक करने के लिए किसका उपयोग करती हैं?",opts:["कुकीज़ (Cookies)","वायरस","फ़ायरवॉल (Firewalls)","MAC एड्रेस"],ans:0,exp:"कुकीज़ वेब सर्वर द्वारा उपयोगकर्ता के ब्राउज़र पर संग्रहीत छोटी टेक्स्ट फ़ाइलें हैं। वे सत्र स्थिति (session state) बनाए रखते हैं, जिससे ई-कॉमर्स साइट उपयोगकर्ता की प्राथमिकताओं, लॉगिन स्थिति और महत्वपूर्ण रूप से वर्चुअल शॉपिंग कार्ट में जोड़े गए आइटम को याद रख सकती है।"}},
{type:"mcq",diff:"medium",en:{q:"What does 3D Secure technology (like Verified by Visa) add to e-commerce transactions?",opts:["3D product images","An extra layer of authentication using a password or OTP for card-not-present transactions","Faster shipping speeds","Virtual reality shopping"],ans:1,exp:"3D Secure (Three-Domain Secure) is an XML-based protocol providing an additional security layer for online credit and debit card transactions. It redirects the user to their issuing bank's portal to authenticate the transaction via a password or OTP."},hi:{q:"3D सिक्योर तकनीक (जैसे Verified by Visa) ई-कॉमर्स लेनदेन में क्या जोड़ती है?",opts:["3D उत्पाद छवियां","कार्ड-नॉट-प्रेजेंट लेनदेन के लिए पासवर्ड या OTP का उपयोग करके प्रमाणीकरण (authentication) की एक अतिरिक्त परत","तेज़ शिपिंग गति","वर्चुअल रियलिटी शॉपिंग"],ans:1,exp:"3D सिक्योर (थ्री-डोमेन सिक्योर) एक XML-आधारित प्रोटोकॉल है जो ऑनलाइन क्रेडिट और डेबिट कार्ड लेनदेन के लिए एक अतिरिक्त सुरक्षा परत प्रदान करता है। यह पासवर्ड या OTP के माध्यम से लेन-देन को प्रमाणित करने के लिए उपयोगकर्ता को उनके जारीकर्ता बैंक के पोर्टल पर रीडायरेक्ट करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following is a network security device that monitors and filters incoming and outgoing network traffic to protect an e-commerce server?",opts:["Router","Switch","Firewall","Hub"],ans:2,exp:"A firewall is a crucial network security system acting as a barrier between an internal e-commerce server network and the untrusted public internet. It utilizes predefined security rules to block malicious traffic and prevent unauthorized access."},hi:{q:"ई-कॉमर्स सर्वर की सुरक्षा के लिए इनकमिंग और आउटगोइंग नेटवर्क ट्रैफ़िक पर नज़र रखने और फ़िल्टर करने वाला नेटवर्क सुरक्षा उपकरण (network security device) निम्नलिखित में से कौन सा है?",opts:["राउटर (Router)","स्विच (Switch)","फ़ायरवॉल (Firewall)","हब (Hub)"],ans:2,exp:"फ़ायरवॉल एक महत्वपूर्ण नेटवर्क सुरक्षा प्रणाली है जो आंतरिक ई-कॉमर्स सर्वर नेटवर्क और अविश्वसनीय सार्वजनिक इंटरनेट के बीच एक बाधा के रूप में कार्य करती है। यह दुर्भावनापूर्ण ट्रैफ़िक को अवरुद्ध करने और अनधिकृत पहुंच को रोकने के लिए पूर्वनिर्धारित सुरक्षा नियमों का उपयोग करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the main function of an SSL Certificate?",opts:["To design web pages","To authenticate the identity of a website and encrypt information sent to the server","To speed up internet connection","To manage product inventory"],ans:1,exp:"An SSL Certificate is a digital certificate binding a cryptographic key to an organization's details. It activates the padlock and HTTPS protocol, providing secure connections from a web server to a browser and authenticating the site's identity."},hi:{q:"SSL प्रमाणपत्र (SSL Certificate) का मुख्य कार्य क्या है?",opts:["वेब पेज डिजाइन करने के लिए","वेबसाइट की पहचान प्रमाणित करने और सर्वर को भेजी गई जानकारी को एन्क्रिप्ट करने के लिए","इंटरनेट कनेक्शन तेज करने के लिए","उत्पाद इन्वेंट्री का प्रबंधन करने के लिए"],ans:1,exp:"SSL प्रमाणपत्र एक डिजिटल प्रमाणपत्र है जो किसी संगठन के विवरण के साथ क्रिप्टोग्राफ़िक कुंजी को बांधता है। यह पैडलॉक और HTTPS प्रोटोकॉल को सक्रिय करता है, वेब सर्वर से ब्राउज़र तक सुरक्षित कनेक्शन प्रदान करता है और साइट की पहचान प्रमाणित करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does PKI stand for in digital security?",opts:["Private Key Information","Public Key Infrastructure","Personal Knowledge Interface","Payment Key Integration"],ans:1,exp:"PKI stands for Public Key Infrastructure. It is a comprehensive framework comprising hardware, software, policies, and standards to manage the creation, administration, distribution, and revocation of digital certificates and public-key encryption."},hi:{q:"डिजिटल सुरक्षा में PKI का पूर्ण रूप क्या है?",opts:["प्राइवेट की इंफॉर्मेशन","पब्लिक की इंफ्रास्ट्रक्चर (Public Key Infrastructure)","पर्सनल नॉलेज इंटरफ़ेस","पेमेंट की इंटीग्रेशन"],ans:1,exp:"PKI का अर्थ पब्लिक की इंफ्रास्ट्रक्चर है। यह एक व्यापक ढांचा है जिसमें डिजिटल प्रमाणपत्रों और सार्वजनिक-कुंजी एन्क्रिप्शन के निर्माण, प्रशासन, वितरण और निरसन (revocation) का प्रबंधन करने के लिए हार्डवेयर, सॉफ्टवेयर, नीतियां और मानक शामिल हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following standards is commonly used for EDI format?",opts:["TCP/IP","HTML","UN/EDIFACT","SMTP"],ans:2,exp:"UN/EDIFACT (United Nations/Electronic Data Interchange for Administration, Commerce and Transport) is the international standard for Electronic Data Interchange. It provides a set of syntax rules to structure data for multi-country, multi-industry exchange."},hi:{q:"EDI प्रारूप के लिए सामान्यतः निम्नलिखित में से किस मानक का उपयोग किया जाता है?",opts:["TCP/IP","HTML","UN/EDIFACT","SMTP"],ans:2,exp:"UN/EDIFACT (यूनाइटेड नेशंस/इलेक्ट्रॉनिक डेटा इंटरचेंज फॉर एडमिनिस्ट्रेशन, कॉमर्स एंड ट्रांसपोर्ट) इलेक्ट्रॉनिक डेटा इंटरचेंज के लिए अंतर्राष्ट्रीय मानक है। यह बहु-देशीय, बहु-उद्योग विनिमय के लिए डेटा संरचना के लिए सिंटैक्स नियमों का एक सेट प्रदान करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Conversion Rate' in e-commerce analytics?",opts:["The currency exchange rate","The percentage of website visitors who complete a desired action, like making a purchase","The speed at which data is converted to encryption","The rate of product returns"],ans:1,exp:"The Conversion Rate is a key performance indicator. It measures the percentage of total website visitors who successfully complete a specific goal, such as purchasing a product, signing up for a newsletter, or filling out a form."},hi:{q:"ई-कॉमर्स एनालिटिक्स में 'कन्वर्ज़न रेट' (Conversion Rate) क्या है?",opts:["मुद्रा विनिमय दर","वेबसाइट के आगंतुकों का प्रतिशत जो एक वांछित क्रिया पूरी करते हैं, जैसे खरीदारी करना","वह गति जिस पर डेटा एन्क्रिप्शन में परिवर्तित होता है","उत्पाद वापसी की दर"],ans:1,exp:"कन्वर्ज़न रेट एक प्रमुख प्रदर्शन संकेतक है। यह कुल वेबसाइट आगंतुकों के प्रतिशत को मापता है जो किसी विशिष्ट लक्ष्य को सफलतापूर्वक पूरा करते हैं, जैसे उत्पाद खरीदना, न्यूज़लेटर के लिए साइन अप करना या फॉर्म भरना।"}},
{type:"mcq",diff:"medium",en:{q:"Which component acts as an intermediary transmitting transaction data between the merchant's website, the payment gateway, and the bank?",opts:["Payment Processor","Shopping Cart","Web Browser","Customer Service"],ans:0,exp:"The Payment Processor executes the actual transaction by transmitting data between the merchant, the acquiring bank, and the issuing bank. While the gateway is the technical front-end, the processor does the heavy lifting of routing the financial data."},hi:{q:"कौन सा घटक व्यापारी की वेबसाइट, पेमेंट गेटवे और बैंक के बीच लेनदेन डेटा संचारित करने वाले मध्यस्थ के रूप में कार्य करता है?",opts:["पेमेंट प्रोसेसर (Payment Processor)","शॉपिंग कार्ट","वेब ब्राउज़र","ग्राहक सेवा"],ans:0,exp:"पेमेंट प्रोसेसर मर्चेंट, एक्वायरिंग बैंक और जारीकर्ता बैंक के बीच डेटा संचारित करके वास्तविक लेनदेन को निष्पादित करता है। जबकि गेटवे तकनीकी फ्रंट-एंड है, प्रोसेसर वित्तीय डेटा को रूट करने का भारी काम करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following defines a Digital Signature?",opts:["A scanned image of a handwritten signature","An electronic mathematical scheme demonstrating the authenticity of a digital message","A password typed at checkout","A physical stamp on a digital screen"],ans:1,exp:"A Digital Signature is an advanced cryptographic mechanism (using asymmetric cryptography) attached to an electronic document to verify the sender's identity (authentication) and ensure the document has not been altered in transit (integrity)."},hi:{q:"निम्नलिखित में से कौन डिजिटल हस्ताक्षर (Digital Signature) को परिभाषित करता है?",opts:["हस्तलिखित हस्ताक्षर की स्कैन की गई छवि","एक डिजिटल संदेश की प्रामाणिकता प्रदर्शित करने वाली एक इलेक्ट्रॉनिक गणितीय योजना (electronic mathematical scheme)","चेकआउट पर टाइप किया गया पासवर्ड","डिजिटल स्क्रीन पर एक भौतिक मुहर"],ans:1,exp:"डिजिटल हस्ताक्षर एक उन्नत क्रिप्टोग्राफ़िक तंत्र है (असममित क्रिप्टोग्राफी का उपयोग करके) जो प्रेषक की पहचान (प्रमाणीकरण) को सत्यापित करने और यह सुनिश्चित करने के लिए एक इलेक्ट्रॉनिक दस्तावेज़ से जुड़ा होता है कि पारगमन (transit) में दस्तावेज़ को बदला नहीं गया है (अखंडता)।"}},
{type:"mcq",diff:"medium",en:{q:"How does an SSL connection typically begin?",opts:["By sending credit card data immediately","With an SSL Handshake to negotiate encryption keys","By verifying the CVV","By downloading a virus scanner"],ans:1,exp:"An SSL session always begins with an 'SSL Handshake'. During this crucial phase, the client and server establish trust, verify certificates, determine the cryptographic algorithms to be used, and securely generate the symmetric session keys for subsequent data encryption."},hi:{q:"SSL कनेक्शन आमतौर पर कैसे शुरू होता है?",opts:["क्रेडिट कार्ड का डेटा तुरंत भेजकर","एन्क्रिप्शन कुंजियों पर बातचीत करने के लिए SSL हैंडशेक (Handshake) के साथ","CVV की पुष्टि करके","वायरस स्कैनर डाउनलोड करके"],ans:1,exp:"एक SSL सत्र हमेशा 'SSL हैंडशेक' के साथ शुरू होता है। इस महत्वपूर्ण चरण के दौरान, क्लाइंट और सर्वर विश्वास स्थापित करते हैं, प्रमाणपत्रों को सत्यापित करते हैं, उपयोग किए जाने वाले क्रिप्टोग्राफ़िक एल्गोरिदम का निर्धारण करते हैं, और बाद के डेटा एन्क्रिप्शन के लिए सममित सत्र कुंजियाँ (symmetric session keys) सुरक्षित रूप से उत्पन्न करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Logistics' in the context of e-commerce?",opts:["Website programming logic","The management of the flow of physical things between the point of origin and the point of consumption","Logical reasoning for pricing","Designing company logos"],ans:1,exp:"Logistics refers to the complex organizational process of managing inventory, warehousing, packaging, and the physical transportation and delivery of goods from the supplier or merchant directly to the final consumer."},hi:{q:"ई-कॉमर्स के संदर्भ में 'लॉजिस्टिक्स' (Logistics) क्या है?",opts:["वेबसाइट प्रोग्रामिंग लॉजिक","उत्पत्ति के बिंदु और उपभोग के बिंदु के बीच भौतिक चीजों के प्रवाह का प्रबंधन","मूल्य निर्धारण के लिए तार्किक तर्क","कंपनी लोगो डिजाइन करना"],ans:1,exp:"लॉजिस्टिक्स से तात्पर्य इन्वेंट्री, वेयरहाउसिंग, पैकेजिंग और आपूर्तिकर्ता या व्यापारी से सीधे अंतिम उपभोक्ता तक माल के भौतिक परिवहन और वितरण के प्रबंधन की जटिल संगठनात्मक प्रक्रिया से है।"}},
{type:"mcq",diff:"medium",en:{q:"What type of card contains an embedded microprocessor chip instead of just a magnetic stripe?",opts:["Flash Card","Smart Card","Punch Card","VGA Card"],ans:1,exp:"A Smart Card (like an EMV chip card) contains an embedded integrated circuit microprocessor. Unlike traditional magnetic stripe cards, smart cards offer robust security by generating dynamic cryptographic data for every single transaction."},hi:{q:"किस प्रकार के कार्ड में केवल मैग्नेटिक स्ट्राइप के बजाय एक एम्बेडेड माइक्रोप्रोसेसर चिप होता है?",opts:["फ्लैश कार्ड","स्मार्ट कार्ड (Smart Card)","पंच कार्ड","VGA कार्ड"],ans:1,exp:"एक स्मार्ट कार्ड (जैसे EMV चिप कार्ड) में एक एम्बेडेड इंटीग्रेटेड सर्किट माइक्रोप्रोसेसर होता है। पारंपरिक मैग्नेटिक स्ट्राइप कार्ड के विपरीत, स्मार्ट कार्ड हर एक लेनदेन के लिए गतिशील क्रिप्टोग्राफ़िक डेटा उत्पन्न करके मजबूत सुरक्षा प्रदान करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary function of a 'Digital Certificate'?",opts:["To provide discounts on shopping","To bind a public key to an entity's identity electronically","To certify completion of a course","To track shipping routes"],ans:1,exp:"A digital certificate (or public key certificate) is an electronic document issued by a Certificate Authority (CA). It uses a digital signature to bind a public key with an identity, allowing users to verify that a public key truly belongs to the specific organization."},hi:{q:"'डिजिटल प्रमाणपत्र' (Digital Certificate) का प्राथमिक कार्य क्या है?",opts:["खरीदारी पर छूट प्रदान करने के लिए","सार्वजनिक कुंजी (public key) को इलेक्ट्रॉनिक रूप से किसी इकाई की पहचान से बांधने के लिए","पाठ्यक्रम पूरा होने को प्रमाणित करने के लिए","शिपिंग मार्गों को ट्रैक करने के लिए"],ans:1,exp:"एक डिजिटल प्रमाणपत्र (या सार्वजनिक कुंजी प्रमाणपत्र) एक प्रमाणपत्र प्राधिकरण (CA) द्वारा जारी किया गया एक इलेक्ट्रॉनिक दस्तावेज़ है। यह एक पहचान के साथ एक सार्वजनिक कुंजी को बांधने के लिए डिजिटल हस्ताक्षर का उपयोग करता है, जिससे उपयोगकर्ता यह सत्यापित कर सकते हैं कि एक सार्वजनिक कुंजी वास्तव में विशिष्ट संगठन की है।"}},
{type:"mcq",diff:"medium",en:{q:"What happens in a DDoS attack against an e-commerce website?",opts:["Data is encrypted","Multiple compromised systems flood the targeted server with traffic to overwhelm it","The database is stolen silently","Credit card numbers are exposed"],ans:1,exp:"A Distributed Denial of Service (DDoS) attack involves a massive network of compromised computers (a botnet) flooding a target web server with an overwhelming amount of fake traffic, consuming its resources and causing the e-commerce site to crash or become unavailable to legitimate users."},hi:{q:"किसी ई-कॉमर्स वेबसाइट के विरुद्ध DDoS हमले में क्या होता है?",opts:["डेटा एन्क्रिप्ट किया जाता है","कई समझौता किए गए सिस्टम लक्षित सर्वर को ट्रैफ़िक से भर देते हैं ताकि उस पर भारी दबाव पड़े","डेटाबेस को चुपचाप चुरा लिया जाता है","क्रेडिट कार्ड नंबर उजागर हो जाते हैं"],ans:1,exp:"डिस्ट्रिब्यूटेड डिनायल ऑफ सर्विस (DDoS) हमले में समझौता किए गए कंप्यूटरों का एक विशाल नेटवर्क (एक बॉटनेट) एक लक्षित वेब सर्वर पर भारी मात्रा में नकली ट्रैफ़िक भेजता है, इसके संसाधनों का उपभोग करता है और ई-कॉमर्स साइट को क्रैश कर देता है या वैध उपयोगकर्ताओं के लिए अनुपलब्ध कर देता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is Web Hosting in the context of creating an e-commerce store?",opts:["Greeting visitors online","A service that provides server space and technologies to view the website on the internet","Designing the website layout","Processing payments"],ans:1,exp:"Web hosting is an essential internet service that allocates secure server space for a website's files and database. For e-commerce, specialized hosting is required to guarantee high uptime, speed, and robust security protocols like SSL."},hi:{q:"ई-कॉमर्स स्टोर बनाने के संदर्भ में वेब होस्टिंग (Web Hosting) क्या है?",opts:["ऑनलाइन आगंतुकों का अभिवादन","एक सेवा जो इंटरनेट पर वेबसाइट देखने के लिए सर्वर स्थान और तकनीक प्रदान करती है","वेबसाइट लेआउट डिजाइन करना","भुगतान संसाधित करना"],ans:1,exp:"वेब होस्टिंग एक आवश्यक इंटरनेट सेवा है जो किसी वेबसाइट की फ़ाइलों और डेटाबेस के लिए सुरक्षित सर्वर स्थान आवंटित करती है। ई-कॉमर्स के लिए, उच्च अपटाइम, गति और SSL जैसे मजबूत सुरक्षा प्रोटोकॉल की गारंटी के लिए विशेष होस्टिंग की आवश्यकता होती है।"}},
{type:"tf",diff:"medium",en:{q:"An HTTP connection (without the 'S') encrypts all credit card details during transmission.",opts:["True","False"],ans:1,exp:"False. Standard HTTP sends data in plain text, meaning any intercepted data (like credit card details) can be easily read by hackers. Only HTTPS (HTTP Secure) uses SSL/TLS protocols to encrypt data during transmission."},hi:{q:"एक HTTP कनेक्शन ('S' के बिना) ट्रांसमिशन के दौरान सभी क्रेडिट कार्ड विवरणों को एन्क्रिप्ट करता है।",opts:["सही","गलत"],ans:1,exp:"गलत। मानक HTTP डेटा को सादे पाठ (plain text) में भेजता है, जिसका अर्थ है कि कोई भी इंटरसेप्टेड डेटा (जैसे क्रेडिट कार्ड विवरण) हैकर्स द्वारा आसानी से पढ़ा जा सकता है। ट्रांसमिशन के दौरान डेटा को एन्क्रिप्ट करने के लिए केवल HTTPS (HTTP सिक्योर) SSL/TLS प्रोटोकॉल का उपयोग करता है।"}},
{type:"tf",diff:"medium",en:{q:"EDI aims to completely replace traditional paper-based business documents like invoices and purchase orders.",opts:["True","False"],ans:0,exp:"True. Electronic Data Interchange (EDI) facilitates the automated, standardized computer-to-computer exchange of critical business documents, significantly reducing manual data entry errors, speeding up processing, and eliminating the need for physical paper documents."},hi:{q:"EDI का उद्देश्य इनवॉइस और खरीद आदेश जैसे पारंपरिक कागज-आधारित व्यावसायिक दस्तावेजों को पूरी तरह से बदलना है।",opts:["सही","गलत"],ans:0,exp:"सही। इलेक्ट्रॉनिक डेटा इंटरचेंज (EDI) महत्वपूर्ण व्यावसायिक दस्तावेजों के स्वचालित, मानकीकृत कंप्यूटर-टू-कंप्यूटर विनिमय की सुविधा प्रदान करता है, जिससे मैन्युअल डेटा प्रविष्टि त्रुटियां कम होती हैं, प्रसंस्करण तेज होता है, और भौतिक कागजी दस्तावेजों की आवश्यकता समाप्त होती है।"}},
{type:"mcq",diff:"hard",en:{q:"Which cryptographic algorithm is famously an example of Asymmetric Key Cryptography widely used in securing e-commerce?",opts:["AES","DES","RSA","Blowfish"],ans:2,exp:"RSA (Rivest-Shamir-Adleman) is a foundational asymmetric cryptographic algorithm. It utilizes a mathematically linked pair of keys—a public key to encrypt data and a private key to decrypt it—making it vital for SSL certificates and digital signatures."},hi:{q:"कौन सा क्रिप्टोग्राफ़िक एल्गोरिदम असममित कुंजी क्रिप्टोग्राफी (Asymmetric Key Cryptography) का एक प्रसिद्ध उदाहरण है जिसका व्यापक रूप से ई-कॉमर्स को सुरक्षित करने में उपयोग किया जाता है?",opts:["AES","DES","RSA","Blowfish"],ans:2,exp:"RSA (रिवेस्ट-शामीर-अदलेमैन) एक मूलभूत असममित क्रिप्टोग्राफ़िक एल्गोरिदम है। यह कुंजियों की एक गणितीय रूप से जुड़ी हुई जोड़ी का उपयोग करता है - डेटा को एन्क्रिप्ट करने के लिए एक सार्वजनिक कुंजी (public key) और इसे डिक्रिप्ट करने के लिए एक निजी कुंजी (private key) - जो इसे SSL प्रमाणपत्रों और डिजिटल हस्ताक्षरों के लिए महत्वपूर्ण बनाती है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the length and location of the CID (Card Identification Data) on an American Express card?",opts:["3 digits on the back","4 digits on the front","4 digits on the back","3 digits on the front"],ans:1,exp:"Unlike Visa or MasterCard which use a 3-digit CVV2 code on the back, American Express uses a 4-digit CID (Card Identification Data) code printed on the front of the card, slightly above the main account number."},hi:{q:"अमेरिकन एक्सप्रेस (American Express) कार्ड पर CID (कार्ड आइडेंटिफिकेशन डेटा) की लंबाई और स्थान क्या है?",opts:["पीछे 3 अंक","सामने 4 अंक","पीछे 4 अंक","सामने 3 अंक"],ans:1,exp:"वीज़ा या मास्टरकार्ड के विपरीत जो पीछे की तरफ 3-अंकीय CVV2 कोड का उपयोग करते हैं, अमेरिकन एक्सप्रेस कार्ड के सामने, मुख्य खाता संख्या के थोड़ा ऊपर मुद्रित 4-अंकीय CID (कार्ड आइडेंटिफिकेशन डेटा) कोड का उपयोग करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What does PCI DSS stand for in the context of e-commerce payment security?",opts:["Payment Card Industry Data Security Standard","Private Credit Institution Digital System Standard","Public Commerce Interface Data Secure System","Payment Compliance Interface Digital Standard"],ans:0,exp:"PCI DSS stands for Payment Card Industry Data Security Standard. It is an extremely strict set of globally recognized security mandates that any organization accepting, transmitting, or storing credit card data must adhere to in order to prevent data breaches."},hi:{q:"ई-कॉमर्स भुगतान सुरक्षा के संदर्भ में PCI DSS का पूर्ण रूप क्या है?",opts:["पेमेंट कार्ड इंडस्ट्री डेटा सिक्योरिटी स्टैंडर्ड","प्राइवेट क्रेडिट इंस्टीट्यूशन डिजिटल सिस्टम स्टैंडर्ड","पब्लिक कॉमर्स इंटरफ़ेस डेटा सिक्योर सिस्टम","पेमेंट कंप्लायंस इंटरफ़ेस डिजिटल स्टैंडर्ड"],ans:0,exp:"PCI DSS का अर्थ पेमेंट कार्ड इंडस्ट्री डेटा सिक्योरिटी स्टैंडर्ड है। यह विश्व स्तर पर मान्यता प्राप्त सुरक्षा जनादेशों का एक अत्यंत सख्त सेट है, जिसका पालन किसी भी संगठन को क्रेडिट कार्ड डेटा को स्वीकार करने, संचारित करने या संग्रहीत करने के लिए करना चाहिए ताकि डेटा उल्लंघनों को रोका जा सके।"}},
{type:"mcq",diff:"hard",en:{q:"The SET (Secure Electronic Transaction) protocol famously utilizes which unique cryptographic mechanism to hide order details from the bank and payment details from the merchant?",opts:["Symmetric Hash","Dual Signatures","Quantum Encryption","Caesar Cipher"],ans:1,exp:"SET employs 'Dual Signatures'. This advanced technique ensures that the merchant can only read the order information (not the credit card data), while the acquiring bank can only read the payment instructions (not the order details), maximizing privacy."},hi:{q:"SET (सिक्योर इलेक्ट्रॉनिक ट्रांजैक्शन) प्रोटोकॉल बैंक से ऑर्डर विवरण और व्यापारी से भुगतान विवरण छिपाने के लिए किस अद्वितीय क्रिप्टोग्राफ़िक तंत्र का उपयोग करता है?",opts:["सममित हैश (Symmetric Hash)","दोहरे हस्ताक्षर (Dual Signatures)","क्वांटम एन्क्रिप्शन","सीज़र सिफर (Caesar Cipher)"],ans:1,exp:"SET 'दोहरे हस्ताक्षर' (Dual Signatures) को नियोजित करता है। यह उन्नत तकनीक सुनिश्चित करती है कि मर्चेंट केवल ऑर्डर की जानकारी (क्रेडिट कार्ड का डेटा नहीं) पढ़ सकता है, जबकि एक्वायरिंग बैंक केवल भुगतान निर्देश (ऑर्डर विवरण नहीं) पढ़ सकता है, जिससे गोपनीयता अधिकतम हो जाती है।"}},
{type:"mcq",diff:"hard",en:{q:"What defines a cryptographic Hash Function in secure digital transactions?",opts:["A two-way function to encrypt and decrypt","A function that converts data of arbitrary size to a fixed-size bit string","A protocol for routing network traffic","A method for physical card verification"],ans:1,exp:"A Hash Function is a deterministic, one-way mathematical algorithm that takes input data of any size and produces a fixed-size output (a hash or message digest). Even a minor change in the input drastically alters the output, ensuring data integrity."},hi:{q:"सुरक्षित डिजिटल लेनदेन में क्रिप्टोग्राफ़िक हैश फ़ंक्शन (Hash Function) को क्या परिभाषित करता है?",opts:["एन्क्रिप्ट और डिक्रिप्ट करने के लिए दो-तरफ़ा फ़ंक्शन","एक फ़ंक्शन जो मनमाने आकार के डेटा को एक निश्चित आकार के बिट स्ट्रिंग में परिवर्तित करता है","नेटवर्क ट्रैफ़िक को रूट करने के लिए एक प्रोटोकॉल","भौतिक कार्ड सत्यापन के लिए एक विधि"],ans:1,exp:"हैश फ़ंक्शन एक नियतात्मक, एकतरफ़ा गणितीय एल्गोरिदम है जो किसी भी आकार का इनपुट डेटा लेता है और एक निश्चित-आकार का आउटपुट (हैश या संदेश डाइजेस्ट) उत्पन्न करता है। इनपुट में मामूली बदलाव भी आउटपुट को काफी बदल देता है, जिससे डेटा अखंडता सुनिश्चित होती है।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following is a dangerous vulnerability where attackers inject malicious SQL statements into e-commerce input fields to manipulate the backend database?",opts:["Cross-Site Scripting (XSS)","SQL Injection","Session Hijacking","Man-in-the-Middle"],ans:1,exp:"SQL Injection (SQLi) is a severe vulnerability. If an e-commerce site fails to sanitize user inputs (like login forms or search bars), attackers can insert SQL commands to bypass authentication, view, delete, or steal sensitive database information."},hi:{q:"निम्नलिखित में से कौन सी एक खतरनाक भेद्यता (vulnerability) है जहां हमलावर बैकएंड डेटाबेस में हेरफेर करने के लिए ई-कॉमर्स इनपुट फ़ील्ड में दुर्भावनापूर्ण SQL कथन इंजेक्ट करते हैं?",opts:["क्रॉस-साइट स्क्रिप्टिंग (XSS)","SQL इंजेक्शन (SQL Injection)","सत्र अपहरण (Session Hijacking)","मैन-इन-द-मिडिल"],ans:1,exp:"SQL इंजेक्शन (SQLi) एक गंभीर भेद्यता है। यदि कोई ई-कॉमर्स साइट उपयोगकर्ता इनपुट (जैसे लॉगिन फॉर्म या सर्च बार) को साफ करने में विफल रहती है, तो हमलावर प्रमाणीकरण को बायपास करने, संवेदनशील डेटाबेस जानकारी देखने, हटाने या चोरी करने के लिए SQL कमांड सम्मिलित कर सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What cyber-attack specifically involves stealing a user's active session cookie to impersonate them on an e-commerce site without needing their password?",opts:["Denial of Service","Phishing","Session Hijacking","Brute Force"],ans:2,exp:"Session Hijacking (or Cookie Hijacking) occurs when an attacker covertly intercepts or steals a valid session cookie. They can then inject this cookie into their own browser, granting them full, unauthorized access to the victim's active e-commerce account."},hi:{q:"किस साइबर-हमले में उपयोगकर्ता के पासवर्ड की आवश्यकता के बिना ई-कॉमर्स साइट पर उनका रूप धारण करने के लिए उपयोगकर्ता की सक्रिय सेशन कुकी (session cookie) को चुराना विशेष रूप से शामिल है?",opts:["डिनायल ऑफ सर्विस","फिशिंग","सत्र अपहरण (Session Hijacking)","ब्रूट फ़ोर्स"],ans:2,exp:"सत्र अपहरण (या कुकी अपहरण) तब होता है जब एक हमलावर गुप्त रूप से एक वैध सत्र कुकी को इंटरसेप्ट या चुरा लेता है। फिर वे इस कुकी को अपने ब्राउज़र में इंजेक्ट कर सकते हैं, जिससे उन्हें पीड़ित के सक्रिय ई-कॉमर्स खाते में पूर्ण, अनधिकृत पहुंच मिल जाती है।"}},
{type:"mcq",diff:"hard",en:{q:"Which standard is widely adopted for securely transmitting Electronic Data Interchange (EDI) messages over the Internet?",opts:["AS2 (Applicability Statement 2)","FTP","Telnet","IMAP"],ans:0,exp:"AS2 (Applicability Statement 2) is a critical B2B messaging protocol used for securely and reliably transporting data (specifically EDI messages) over the Internet using HTTP/HTTPS, digital certificates, and encryption for non-repudiation."},hi:{q:"इंटरनेट पर इलेक्ट्रॉनिक डेटा इंटरचेंज (EDI) संदेशों को सुरक्षित रूप से प्रसारित करने के लिए किस मानक को व्यापक रूप से अपनाया गया है?",opts:["AS2 (एप्लिकेबिलिटी स्टेटमेंट 2)","FTP","टेल्नेट (Telnet)","IMAP"],ans:0,exp:"AS2 (एप्लिकेबिलिटी स्टेटमेंट 2) एक महत्वपूर्ण B2B मैसेजिंग प्रोटोकॉल है जिसका उपयोग HTTP/HTTPS, डिजिटल प्रमाणपत्रों और गैर-अस्वीकरण के लिए एन्क्रिप्शन का उपयोग करके इंटरनेट पर डेटा (विशेष रूप से EDI संदेश) को सुरक्षित और विश्वसनीय रूप से ले जाने के लिए किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"In payment gateway architecture, what is 'Tokenization'?",opts:["Distributing physical tokens to customers","Replacing sensitive card data with a unique surrogate identifier (a token)","Encrypting passwords using RSA","Mining cryptocurrencies for payment"],ans:1,exp:"Tokenization replaces highly sensitive cardholder data (like the PAN) with a unique, meaningless string of characters called a token. Even if an e-commerce merchant's database is breached, hackers only steal useless tokens, dramatically improving security."},hi:{q:"पेमेंट गेटवे आर्किटेक्चर में, 'टोकनाइजेशन' (Tokenization) क्या है?",opts:["ग्राहकों को भौतिक टोकन वितरित करना","संवेदनशील कार्ड डेटा को एक अद्वितीय सरोगेट पहचानकर्ता (एक टोकन) के साथ बदलना","RSA का उपयोग करके पासवर्ड एन्क्रिप्ट करना","भुगतान के लिए क्रिप्टोकरेंसी माइनिंग करना"],ans:1,exp:"टोकनाइजेशन अत्यधिक संवेदनशील कार्डधारक डेटा (जैसे पैन) को टोकन नामक वर्णों की एक अद्वितीय, अर्थहीन स्ट्रिंग से बदल देता है। भले ही ई-कॉमर्स मर्चेंट के डेटाबेस का उल्लंघन किया गया हो, हैकर्स केवल बेकार टोकन चुराते हैं, जिससे सुरक्षा में नाटकीय रूप से सुधार होता है।"}},
{type:"mcq",diff:"hard",en:{q:"Comparing cryptographic methods, what is the primary operational difference between Symmetric and Asymmetric encryption?",opts:["Symmetric uses two keys, Asymmetric uses one key","Symmetric is generally much faster than Asymmetric","Asymmetric is easily crackable","Symmetric cannot be used for local storage"],ans:1,exp:"Symmetric encryption utilizes a single shared key for both encryption and decryption, making it computationally very fast and efficient for bulk data. Asymmetric encryption uses a public/private key pair, solving key distribution issues but requiring significantly more processing time."},hi:{q:"क्रिप्टोग्राफ़िक विधियों की तुलना में, सममित (Symmetric) और असममित (Asymmetric) एन्क्रिप्शन के बीच प्राथमिक परिचालन अंतर क्या है?",opts:["सममित दो कुंजियों का उपयोग करता है, असममित एक कुंजी का उपयोग करता है","सममित आम तौर पर असममित की तुलना में बहुत तेज है","असममित को आसानी से क्रैक किया जा सकता है","सममित का उपयोग स्थानीय भंडारण के लिए नहीं किया जा सकता है"],ans:1,exp:"सममित एन्क्रिप्शन एन्क्रिप्शन और डिक्रिप्शन दोनों के लिए एक ही साझा कुंजी का उपयोग करता है, जिससे यह कम्प्यूटेशनल रूप से बहुत तेज़ और बल्क डेटा के लिए कुशल हो जाता है। असममित एन्क्रिप्शन एक सार्वजनिक/निजी कुंजी जोड़ी का उपयोग करता है, जो कुंजी वितरण समस्याओं को हल करता है लेकिन महत्वपूर्ण रूप से अधिक प्रसंस्करण समय की आवश्यकता होती है।"}},
{type:"mcq",diff:"hard",en:{q:"In a Public Key Infrastructure (PKI), what is the role of the Certificate Authority (CA)?",opts:["To generate credit card numbers","To act as a trusted third party that validates identities and issues digital certificates","To host the e-commerce website","To block DDoS attacks"],ans:1,exp:"A Certificate Authority (CA), such as VeriSign or Let's Encrypt, is a highly trusted overarching entity in a PKI. It rigorously verifies the identity of an individual or organization before issuing and signing a digital certificate, linking their public key to their identity."},hi:{q:"पब्लिक की इंफ्रास्ट्रक्चर (PKI) में, प्रमाणपत्र प्राधिकरण (Certificate Authority - CA) की क्या भूमिका है?",opts:["क्रेडिट कार्ड नंबर जनरेट करना","एक विश्वसनीय तृतीय पक्ष के रूप में कार्य करना जो पहचान को मान्य करता है और डिजिटल प्रमाणपत्र जारी करता है","ई-कॉमर्स वेबसाइट को होस्ट करना","DDoS हमलों को रोकना"],ans:1,exp:"एक प्रमाणपत्र प्राधिकरण (CA), जैसे कि VeriSign या Let's Encrypt, PKI में एक अत्यधिक विश्वसनीय अतिव्यापी इकाई है। यह डिजिटल प्रमाणपत्र जारी करने और हस्ताक्षर करने से पहले किसी व्यक्ति या संगठन की पहचान को कठोरता से सत्यापित करता है, उनकी सार्वजनिक कुंजी को उनकी पहचान से जोड़ता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which cyber-attack involves a hacker secretly intercepting and possibly altering communications between a shopper and a payment gateway?",opts:["Spoofing","SQL Injection","Man-in-the-Middle (MitM) attack","Ransomware"],ans:2,exp:"In a Man-in-the-Middle (MitM) attack, the perpetrator positions themselves logically between the client and the server. They eavesdrop on the connection, intercepting, reading, or modifying data in real-time, often exploiting unsecured public Wi-Fi networks."},hi:{q:"किस साइबर-हमले में हैकर द्वारा गुप्त रूप से खरीदार और पेमेंट गेटवे के बीच संचार को इंटरसेप्ट करना और संभवतः बदलना शामिल है?",opts:["स्पूफिंग","SQL इंजेक्शन","मैन-इन-द-मिडिल (MitM) अटैक","रैनसमवेयर (Ransomware)"],ans:2,exp:"एक मैन-इन-द-मिडिल (MitM) हमले में, अपराधी खुद को तार्किक रूप से क्लाइंट और सर्वर के बीच स्थापित करता है। वे कनेक्शन पर छिपकर बात सुनते हैं, वास्तविक समय में डेटा को रोकते हैं, पढ़ते हैं या संशोधित करते हैं, अक्सर असुरक्षित सार्वजनिक वाई-फाई नेटवर्क का फायदा उठाते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What is 'A/B Testing' primarily used for in e-commerce optimization?",opts:["Testing credit card validity","Comparing two versions of a webpage to see which performs better in generating conversions","Testing the firewall strength","Testing two different shipping companies"],ans:1,exp:"A/B testing (or split testing) is a highly analytical methodology where user traffic is split between two distinct variations (A and B) of a webpage. Analysts track metrics to determine which variation yields higher conversion rates, optimizing the UI/UX."},hi:{q:"ई-कॉमर्स ऑप्टिमाइज़ेशन में 'A/B टेस्टिंग' (A/B Testing) का मुख्य रूप से किस लिए उपयोग किया जाता है?",opts:["क्रेडिट कार्ड की वैधता का परीक्षण","वेबपेज के दो संस्करणों की तुलना यह देखने के लिए करना कि रूपांतरण (conversions) उत्पन्न करने में कौन सा बेहतर प्रदर्शन करता है","फ़ायरवॉल की ताकत का परीक्षण","दो अलग-अलग शिपिंग कंपनियों का परीक्षण"],ans:1,exp:"A/B परीक्षण (या स्प्लिट परीक्षण) एक अत्यधिक विश्लेषणात्मक पद्धति है जहां उपयोगकर्ता ट्रैफ़िक को वेबपेज की दो अलग-अलग विविधताओं (A और B) के बीच विभाजित किया जाता है। विश्लेषक यह निर्धारित करने के लिए मीट्रिक ट्रैक करते हैं कि कौन सा रूपांतरण उच्च रूपांतरण दर (conversion rates) प्राप्त करता है, UI/UX का अनुकूलन करता है।"}},
{type:"mcq",diff:"hard",en:{q:"What does 'Omni-channel' e-commerce refer to?",opts:["Selling only on one specific website","A fully-integrated approach providing a seamless shopping experience across all online and physical channels","Using omni-directional antennas for Wi-Fi","Selling products globally"],ans:1,exp:"Omni-channel retail is an advanced, holistic strategy. It seamlessly integrates desktop websites, mobile apps, social media, and brick-and-mortar stores. This ensures a customer has a completely unified and consistent experience across all touchpoints."},hi:{q:"'ओमनी-चैनल' (Omni-channel) ई-कॉमर्स क्या दर्शाता है?",opts:["केवल एक विशिष्ट वेबसाइट पर बेचना","सभी ऑनलाइन और भौतिक चैनलों पर एक सहज खरीदारी अनुभव प्रदान करने वाला एक पूर्ण-एकीकृत दृष्टिकोण","वाई-फाई के लिए ओमनी-डायरेक्शनल एंटेना का उपयोग करना","विश्व स्तर पर उत्पाद बेचना"],ans:1,exp:"ओमनी-चैनल रिटेल एक उन्नत, समग्र रणनीति है। यह डेस्कटॉप वेबसाइटों, मोबाइल ऐप, सोशल मीडिया और ईंट-और-मोर्टार (brick-and-mortar) स्टोर को सहजता से एकीकृत करता है। यह सुनिश्चित करता है कि ग्राहक को सभी टचप्वाइंट पर पूरी तरह से एकीकृत और सुसंगत अनुभव प्राप्त हो।"}},
{type:"mcq",diff:"hard",en:{q:"Which of the following describes Supply Chain Management (SCM) integration in e-commerce?",opts:["Designing product graphics","Managing the continuous flow of goods, data, and finances related to a product from supplier to consumer","Managing employee payroll","Optimizing search engine keywords"],ans:1,exp:"SCM integration connects an e-commerce platform directly to backend logistics networks. It involves the intricate coordination of purchasing, manufacturing, inventory management, warehousing, and transportation to ensure efficient product delivery."},hi:{q:"निम्नलिखित में से कौन ई-कॉमर्स में सप्लाई चेन मैनेजमेंट (SCM) एकीकरण का वर्णन करता है?",opts:["उत्पाद ग्राफिक्स डिजाइन करना","आपूर्तिकर्ता से उपभोक्ता तक किसी उत्पाद से संबंधित वस्तुओं, डेटा और वित्त के निरंतर प्रवाह का प्रबंधन करना","कर्मचारी पेरोल का प्रबंधन","खोज इंजन कीवर्ड का अनुकूलन"],ans:1,exp:"SCM एकीकरण एक ई-कॉमर्स प्लेटफॉर्म को सीधे बैकएंड लॉजिस्टिक्स नेटवर्क से जोड़ता है। इसमें कुशल उत्पाद वितरण सुनिश्चित करने के लिए क्रय, विनिर्माण, इन्वेंट्री प्रबंधन, वेयरहाउसिंग और परिवहन का जटिल समन्वय शामिल है।"}},
{type:"mcq",diff:"hard",en:{q:"Why do large e-commerce enterprises integrate their websites with an ERP (Enterprise Resource Planning) system?",opts:["To create graphical animations","To achieve real-time synchronization of inventory, customer data, and financials across all business departments","To prevent DDoS attacks exclusively","To replace the HTML code"],ans:1,exp:"ERP integration acts as the central nervous system for massive e-commerce operations. It ensures that front-end sales data instantly updates backend systems, automating inventory deductions, accounting ledgers, and CRM records without manual intervention."},hi:{q:"बड़े ई-कॉमर्स उद्यम अपनी वेबसाइटों को ERP (एंटरप्राइज रिसोर्स प्लानिंग) सिस्टम के साथ एकीकृत क्यों करते हैं?",opts:["ग्राफिकल एनिमेशन बनाने के लिए","सभी व्यावसायिक विभागों में इन्वेंट्री, ग्राहक डेटा और वित्तीय के वास्तविक समय सिंक्रनाइज़ेशन को प्राप्त करने के लिए","विशेष रूप से DDoS हमलों को रोकने के लिए","HTML कोड को बदलने के लिए"],ans:1,exp:"ERP एकीकरण बड़े ई-कॉमर्स संचालन के लिए केंद्रीय तंत्रिका तंत्र के रूप में कार्य करता है। यह सुनिश्चित करता है कि फ्रंट-एंड बिक्री डेटा तुरंत बैकएंड सिस्टम को अपडेट करता है, मैन्युअल हस्तक्षेप के बिना इन्वेंट्री कटौती, अकाउंटिंग लेजर और CRM रिकॉर्ड को स्वचालित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which defense mechanism is vital to prevent Cross-Site Scripting (XSS) attacks on an e-commerce product review page?",opts:["Using longer passwords","Strict input validation and rigorous output encoding","Installing a faster hard drive","Upgrading to HTML5"],ans:1,exp:"In an XSS attack, a hacker injects malicious client-side scripts into a webpage viewed by others. To prevent this, developers must strictly validate all user input (like reviews) and contextually encode output so the browser treats it as harmless text, not executable code."},hi:{q:"ई-कॉमर्स उत्पाद समीक्षा पृष्ठ (product review page) पर क्रॉस-साइट स्क्रिप्टिंग (XSS) हमलों को रोकने के लिए कौन सा रक्षा तंत्र महत्वपूर्ण है?",opts:["लंबे पासवर्ड का उपयोग करना","सख्त इनपुट सत्यापन (input validation) और कठोर आउटपुट एन्कोडिंग","तेज़ हार्ड ड्राइव स्थापित करना","HTML5 में अपग्रेड करना"],ans:1,exp:"XSS हमले में, एक हैकर दूसरों द्वारा देखे गए वेबपेज में दुर्भावनापूर्ण क्लाइंट-साइड स्क्रिप्ट इंजेक्ट करता है। इसे रोकने के लिए, डेवलपर्स को सभी उपयोगकर्ता इनपुट (जैसे समीक्षाएं) को सख्ती से मान्य करना चाहिए और प्रासंगिक रूप से आउटपुट को एन्कोड करना चाहिए ताकि ब्राउज़र इसे हानिरहित टेक्स्ट के रूप में माने, न कि निष्पादन योग्य कोड के रूप में।"}},
{type:"mcq",diff:"hard",en:{q:"At which layer of the OSI model does the SSL/TLS protocol conceptually operate to secure e-commerce transactions?",opts:["Layer 2 (Data Link)","Layer 3 (Network)","Between Layer 4 (Transport) and Layer 7 (Application)","Layer 1 (Physical)"],ans:2,exp:"SSL/TLS is highly complex; while it is often described as operating at the Transport Layer (Layer 4) because it secures transport connections, it requires application-layer data to function. Thus, it conceptually sits between the Application and Transport layers."},hi:{q:"OSI मॉडल की किस परत (layer) पर SSL/TLS प्रोटोकॉल वैचारिक रूप से ई-कॉमर्स लेनदेन को सुरक्षित करने के लिए संचालित होता है?",opts:["लेयर 2 (डेटा लिंक)","लेयर 3 (नेटवर्क)","लेयर 4 (ट्रांसपोर्ट) और लेयर 7 (एप्लीकेशन) के बीच","लेयर 1 (फिजिकल)"],ans:2,exp:"SSL/TLS अत्यधिक जटिल है; हालाँकि इसे अक्सर ट्रांसपोर्ट लेयर (लेयर 4) पर काम करने के रूप में वर्णित किया जाता है क्योंकि यह ट्रांसपोर्ट कनेक्शन को सुरक्षित करता है, इसे काम करने के लिए एप्लिकेशन-लेयर डेटा की आवश्यकता होती है। इस प्रकार, यह वैचारिक रूप से एप्लिकेशन और ट्रांसपोर्ट लेयर्स के बीच बैठता है।"}},
{type:"mcq",diff:"hard",en:{q:"In e-commerce security, what defines a 'Zero-Day Exploit'?",opts:["An attack happening at midnight","A cyber-attack that targets a software vulnerability completely unknown to the vendor and antivirus companies","A virus that deletes all files in zero days","An expired SSL certificate"],ans:1,exp:"A Zero-Day Exploit is incredibly dangerous. It occurs when hackers discover and exploit a software vulnerability before the software creators even know it exists, giving the vendor 'zero days' to create a patch or defense, leaving e-commerce sites highly exposed."},hi:{q:"ई-कॉमर्स सुरक्षा में, 'ज़ीरो-डे एक्सप्लॉइट' (Zero-Day Exploit) क्या परिभाषित करता है?",opts:["आधी रात को होने वाला हमला","एक साइबर-हमला जो एक सॉफ्टवेयर भेद्यता को लक्षित करता है जो विक्रेता और एंटीवायरस कंपनियों के लिए पूरी तरह से अज्ञात है","एक वायरस जो शून्य दिनों में सभी फाइलों को हटा देता है","एक समाप्त (expired) SSL प्रमाणपत्र"],ans:1,exp:"एक जीरो-डे एक्सप्लॉइट अविश्वसनीय रूप से खतरनाक है। यह तब होता है जब हैकर्स सॉफ़्टवेयर रचनाकारों को इसके अस्तित्व के बारे में जानने से पहले ही सॉफ़्टवेयर भेद्यता की खोज और शोषण करते हैं, विक्रेता को पैच या रक्षा बनाने के लिए 'शून्य दिन' देते हैं, जिससे ई-कॉमर्स साइट अत्यधिक असुरक्षित हो जाती हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Why do e-commerce checkout systems frequently implement CAPTCHA challenges?",opts:["To test the user's intelligence","To prevent automated bot networks from executing rapid credential stuffing or fraudulent card-testing attacks","To improve the website's graphical design","To calculate shipping costs faster"],ans:1,exp:"CAPTCHA (Completely Automated Public Turing test to tell Computers and Humans Apart) acts as a critical friction point. It blocks automated scripts and botnets from brute-forcing login pages or systematically testing stolen credit card numbers (carding) at checkout."},hi:{q:"ई-कॉमर्स चेकआउट सिस्टम अक्सर CAPTCHA चुनौतियों को क्यों लागू करते हैं?",opts:["उपयोगकर्ता की बुद्धि का परीक्षण करने के लिए","स्वचालित बॉट नेटवर्क को तीव्र क्रेडेंशियल स्टफिंग या धोखाधड़ी वाले कार्ड-परीक्षण हमलों को निष्पादित करने से रोकने के लिए","वेबसाइट के ग्राफिकल डिजाइन को बेहतर बनाने के लिए","शिपिंग लागत की तेजी से गणना करने के लिए"],ans:1,exp:"CAPTCHA (Completely Automated Public Turing test to tell Computers and Humans Apart) एक महत्वपूर्ण घर्षण बिंदु के रूप में कार्य करता है। यह स्वचालित स्क्रिप्ट और बॉटनेट को लॉगिन पेजों पर ब्रूट-फोर्सिंग करने या चेकआउट पर चोरी किए गए क्रेडिट कार्ड नंबर (कार्डिंग) का व्यवस्थित रूप से परीक्षण करने से रोकता है।"}},
{type:"mcq",diff:"hard",en:{q:"How is the 'Cart Abandonment Rate' calculated mathematically in e-commerce analytics?",opts:["Total Carts / Total Visitors","1 - (Completed Purchases / Total Opened Carts)","Completed Purchases / Total Opened Carts","Total Items / Total Carts"],ans:1,exp:"The cart abandonment rate is calculated by dividing the total number of completed purchases by the number of created shopping carts. Subtracting that fraction from 1 (or 100%) gives the percentage of users who loaded a cart but failed to check out."},hi:{q:"ई-कॉमर्स एनालिटिक्स में गणितीय रूप से 'कार्ट एबेंडनमेंट रेट' (Cart Abandonment Rate) की गणना कैसे की जाती है?",opts:["कुल कार्ट / कुल विज़िटर","1 - (पूरी की गई खरीदारी / कुल खोले गए कार्ट)","पूरी की गई खरीदारी / कुल खोले गए कार्ट","कुल आइटम / कुल कार्ट"],ans:1,exp:"कार्ट परित्याग दर (cart abandonment rate) की गणना बनाए गए शॉपिंग कार्ट की संख्या से पूरी की गई खरीदारी की कुल संख्या को विभाजित करके की जाती है। उस अंश को 1 (या 100%) से घटाने पर उन उपयोगकर्ताओं का प्रतिशत प्राप्त होता है जिन्होंने कार्ट लोड किया लेकिन चेक आउट करने में विफल रहे।"}},
{type:"mcq",diff:"hard",en:{q:"What is Magento (now Adobe Commerce) in the e-commerce ecosystem?",opts:["An antivirus program","A robust, open-source e-commerce platform written in PHP designed for highly customizable online stores","A specific payment gateway","A social media network"],ans:1,exp:"Magento is a highly advanced, open-source e-commerce platform built on PHP. It provides immense flexibility and control over the look, content, and functionality of an online store, heavily utilized by large-scale enterprise e-commerce operations."},hi:{q:"ई-कॉमर्स पारिस्थितिकी तंत्र में मैगेंटो (Magento - अब Adobe Commerce) क्या है?",opts:["एक एंटीवायरस प्रोग्राम","अत्यधिक अनुकूलन योग्य ऑनलाइन स्टोर के लिए डिज़ाइन किया गया PHP में लिखा गया एक मजबूत, ओपन-सोर्स ई-कॉमर्स प्लेटफ़ॉर्म","एक विशिष्ट पेमेंट गेटवे","एक सोशल मीडिया नेटवर्क"],ans:1,exp:"मैगेंटो PHP पर बना एक अत्यधिक उन्नत, ओपन-सोर्स ई-कॉमर्स प्लेटफॉर्म है। यह ऑनलाइन स्टोर के रूप, सामग्री और कार्यक्षमता पर अत्यधिक लचीलापन और नियंत्रण प्रदान करता है, जिसका उपयोग बड़े पैमाने पर उद्यम ई-कॉमर्स संचालन द्वारा भारी मात्रा में किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What is the precise purpose of an Address Verification System (AVS) during a credit card transaction?",opts:["To deliver the product to the correct home","To verify that the billing address entered by the customer exactly matches the address on file with the issuing bank","To find the customer's IP address","To translate website languages"],ans:1,exp:"The Address Verification System (AVS) is a fraud-prevention tool. When a transaction is processed, it checks the numeric portions of the customer's submitted billing address (like the zip code) against the records stored by the credit card's issuing bank."},hi:{q:"क्रेडिट कार्ड लेनदेन के दौरान एड्रेस वेरिफिकेशन सिस्टम (AVS) का सटीक उद्देश्य क्या है?",opts:["उत्पाद को सही घर तक पहुंचाना","यह सत्यापित करना कि ग्राहक द्वारा दर्ज किया गया बिलिंग पता जारीकर्ता बैंक के पास मौजूद पते से बिल्कुल मेल खाता है","ग्राहक का IP पता खोजना","वेबसाइट भाषाओं का अनुवाद करना"],ans:1,exp:"एड्रेस वेरिफिकेशन सिस्टम (AVS) धोखाधड़ी-रोकथाम उपकरण है। जब कोई लेन-देन संसाधित किया जाता है, तो यह ग्राहक के सबमिट किए गए बिलिंग पते (जैसे ज़िप कोड) के संख्यात्मक भागों की क्रेडिट कार्ड के जारीकर्ता बैंक द्वारा संग्रहीत रिकॉर्ड से जाँच करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In payment processing, what defines a 'Virtual Terminal'?",opts:["A VR headset for shopping","A secure web-based application allowing merchants to manually enter customer credit card details for phone or mail orders","A physical POS machine","A dummy terminal for testing codes"],ans:1,exp:"A Virtual Terminal is a software application provided by a payment gateway. It allows merchants to accept payments without physical card-swiping hardware by manually keying in the customer's credit card information (MOTO - Mail Order/Telephone Order)."},hi:{q:"पेमेंट प्रोसेसिंग में, 'वर्चुअल टर्मिनल' (Virtual Terminal) क्या परिभाषित करता है?",opts:["खरीदारी के लिए एक VR हेडसेट","एक सुरक्षित वेब-आधारित एप्लिकेशन जो व्यापारियों को फोन या मेल ऑर्डर के लिए मैन्युअल रूप से ग्राहक क्रेडिट कार्ड विवरण दर्ज करने की अनुमति देता है","एक भौतिक POS मशीन","कोड के परीक्षण के लिए एक डमी टर्मिनल"],ans:1,exp:"वर्चुअल टर्मिनल एक पेमेंट गेटवे द्वारा प्रदान किया गया एक सॉफ्टवेयर एप्लिकेशन है। यह व्यापारियों को ग्राहक की क्रेडिट कार्ड की जानकारी (MOTO - मेल ऑर्डर/टेलीफोन ऑर्डर) मैन्युअल रूप से दर्ज करके भौतिक कार्ड-स्वाइपिंग हार्डवेयर के बिना भुगतान स्वीकार करने की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which specific phase of the Application Development Life Cycle (ADLC) focuses intensely on verifying that the e-commerce software is completely free of bugs and secure before deployment?",opts:["Design Phase","Requirements Gathering","Testing Phase","Maintenance Phase"],ans:2,exp:"The Testing Phase in the ADLC is absolutely critical for e-commerce. Quality Assurance (QA) teams conduct rigorous functional, performance, and security testing (like penetration testing) to identify and eradicate vulnerabilities and software bugs prior to live deployment."},hi:{q:"एप्लिकेशन डेवलपमेंट लाइफ साइकिल (ADLC) का कौन सा विशिष्ट चरण परिनियोजन (deployment) से पहले यह सत्यापित करने पर तीव्रता से ध्यान केंद्रित करता है कि ई-कॉमर्स सॉफ्टवेयर पूरी तरह से बग-मुक्त और सुरक्षित है?",opts:["डिज़ाइन चरण","आवश्यकताएँ एकत्रित करना","परीक्षण (Testing) चरण","रखरखाव (Maintenance) चरण"],ans:2,exp:"ADLC में परीक्षण चरण (Testing Phase) ई-कॉमर्स के लिए बिल्कुल महत्वपूर्ण है। गुणवत्ता आश्वासन (QA) टीमें लाइव परिनियोजन से पहले कमजोरियों और सॉफ्टवेयर बग की पहचान करने और उन्हें खत्म करने के लिए कठोर कार्यात्मक, प्रदर्शन और सुरक्षा परीक्षण (जैसे प्रवेश परीक्षण) आयोजित करती हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Within a typical E-commerce Database Schema, which SQL constraint strictly ensures that an 'Order' cannot be generated for a 'Customer_ID' that does not exist in the Customers table?",opts:["UNIQUE constraint","PRIMARY KEY constraint","NOT NULL constraint","FOREIGN KEY constraint"],ans:3,exp:"A FOREIGN KEY is a relational database constraint that enforces referential integrity. By linking the 'Customer_ID' in the Orders table to the PRIMARY KEY in the Customers table, it mathematically guarantees that ghost orders cannot be created for non-existent users."},hi:{q:"एक विशिष्ट ई-कॉमर्स डेटाबेस स्कीमा के भीतर, कौन सा SQL प्रतिबंध (constraint) कड़ाई से यह सुनिश्चित करता है कि ऐसे 'Customer_ID' के लिए 'ऑर्डर' (Order) उत्पन्न नहीं किया जा सकता है जो ग्राहक (Customers) तालिका में मौजूद नहीं है?",opts:["UNIQUE constraint","PRIMARY KEY constraint","NOT NULL constraint","FOREIGN KEY constraint"],ans:3,exp:"एक फॉरेन की (FOREIGN KEY) एक रिलेशनल डेटाबेस प्रतिबंध है जो संदर्भात्मक अखंडता (referential integrity) लागू करता है। ऑर्डर्स टेबल में 'Customer_ID' को कस्टमर्स टेबल में प्राइमरी की से जोड़कर, यह गणितीय रूप से गारंटी देता है कि गैर-मौजूद उपयोगकर्ताओं के लिए घोस्ट ऑर्डर नहीं बनाए जा सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which advanced pricing algorithm dynamically alters e-commerce product prices in real-time based on supply, demand, competitor pricing, and user behavior?",opts:["Static Pricing","Dynamic Pricing (Surge Pricing)","Cost-Plus Pricing","Penetration Pricing"],ans:1,exp:"Dynamic Pricing is a highly complex algorithmic strategy. E-commerce giants (like Amazon or airlines) use massive AI datasets to constantly fluctuate prices in real-time, capitalizing on immediate demand spikes, inventory dips, or specific user profiling to maximize profit margins."},hi:{q:"कौन सा उन्नत मूल्य निर्धारण एल्गोरिदम आपूर्ति, मांग, प्रतिस्पर्धी मूल्य निर्धारण और उपयोगकर्ता व्यवहार के आधार पर वास्तविक समय में ई-कॉमर्स उत्पाद की कीमतों को गतिशील रूप से बदलता है?",opts:["स्टेटिक मूल्य निर्धारण","गतिशील मूल्य निर्धारण (Dynamic Pricing / Surge Pricing)","लागत-प्लस मूल्य निर्धारण","पेनेट्रेशन मूल्य निर्धारण"],ans:1,exp:"डायनेमिक प्राइसिंग एक अत्यधिक जटिल एल्गोरिथम रणनीति है। ई-कॉमर्स दिग्गज (जैसे अमेज़ॅन या एयरलाइंस) लाभ मार्जिन को अधिकतम करने के लिए तत्काल मांग में वृद्धि, इन्वेंट्री में गिरावट, या विशिष्ट उपयोगकर्ता प्रोफाइलिंग का लाभ उठाते हुए, वास्तविक समय में कीमतों में लगातार उतार-चढ़ाव करने के लिए बड़े पैमाने पर एआई डेटासेट का उपयोग करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically does the IT Act, 2000 of India provide legal recognition for in the context of E-commerce?",opts:["Physical postal mail","Electronic records and Digital Signatures","Cryptocurrency mining","Software piracy"],ans:1,exp:"The Information Technology Act, 2000 is a landmark Indian law. It provides critical legal recognition for transactions carried out by means of electronic data interchange, granting absolute legal validity to electronic records and Digital Signatures under the framework of e-commerce."},hi:{q:"ई-कॉमर्स के संदर्भ में भारत का आईटी अधिनियम, 2000 विशेष रूप से किस बात को कानूनी मान्यता प्रदान करता है?",opts:["भौतिक डाक मेल","इलेक्ट्रॉनिक रिकॉर्ड और डिजिटल हस्ताक्षर","क्रिप्टोक्यूरेंसी माइनिंग","सॉफ्टवेयर चोरी (piracy)"],ans:1,exp:"सूचना प्रौद्योगिकी अधिनियम, 2000 एक ऐतिहासिक भारतीय कानून है। यह इलेक्ट्रॉनिक डेटा इंटरचेंज के माध्यम से किए गए लेनदेन के लिए महत्वपूर्ण कानूनी मान्यता प्रदान करता है, ई-कॉमर्स के ढांचे के तहत इलेक्ट्रॉनिक रिकॉर्ड और डिजिटल हस्ताक्षर को पूर्ण कानूनी वैधता प्रदान करता है।"}},
{type:"tf",diff:"hard",en:{q:"Tokenization permanently stores the actual 16-digit credit card numbers within the e-commerce merchant's local database for faster future checkout.",opts:["True","False"],ans:1,exp:"False. The entire purpose of tokenization is to completely eliminate the actual 16-digit Primary Account Number (PAN) from the merchant's local database. It replaces the PAN with a meaningless token, while the actual card data is stored safely in the payment processor's secure vault."},hi:{q:"भविष्य में तेज़ चेकआउट के लिए टोकनाइजेशन (Tokenization) स्थायी रूप से वास्तविक 16-अंकीय क्रेडिट कार्ड नंबरों को ई-कॉमर्स मर्चेंट के स्थानीय डेटाबेस में संग्रहीत करता है।",opts:["सही","गलत"],ans:1,exp:"गलत। टोकनाइजेशन का पूरा उद्देश्य मर्चेंट के स्थानीय डेटाबेस से वास्तविक 16-अंकीय प्राइमरी अकाउंट नंबर (PAN) को पूरी तरह से खत्म करना है। यह PAN को अर्थहीन टोकन से बदल देता है, जबकि वास्तविक कार्ड डेटा पेमेंट प्रोसेसर के सुरक्षित वॉल्ट में सुरक्षित रूप से संग्रहीत होता है।"}},
{type:"tf",diff:"hard",en:{q:"PCI DSS compliance is absolutely mandatory for any e-commerce merchant that accepts, processes, or transmits credit card payments.",opts:["True","False"],ans:0,exp:"True. Payment Card Industry Data Security Standard (PCI DSS) compliance is a strict, non-negotiable requirement mandated by major credit card brands (Visa, Mastercard) to ensure all companies that process, store, or transmit credit card information maintain a secure environment."},hi:{q:"क्रेडिट कार्ड से भुगतान स्वीकार करने, संसाधित करने या संचारित करने वाले किसी भी ई-कॉमर्स मर्चेंट के लिए PCI DSS अनुपालन बिल्कुल अनिवार्य है।",opts:["सही","गलत"],ans:0,exp:"सही। पेमेंट कार्ड इंडस्ट्री डेटा सिक्योरिटी स्टैंडर्ड (PCI DSS) अनुपालन एक सख्त, गैर-परक्राम्य (non-negotiable) आवश्यकता है जो प्रमुख क्रेडिट कार्ड ब्रांडों (वीज़ा, मास्टरकार्ड) द्वारा अनिवार्य है ताकि यह सुनिश्चित किया जा सके कि क्रेडिट कार्ड की जानकारी को संसाधित करने, संग्रहीत करने या संचारित करने वाली सभी कंपनियां एक सुरक्षित वातावरण बनाए रखें।"}}
];
